import { Order, OrderStatus, Product, Customer, BankConfig, Notification, ShopConfig, ImportRecord, PaymentMethod } from '../types';
import { db } from '../firebaseConfig';
import { v4 as uuidv4 } from 'uuid';
import { 
  collection, 
  setDoc, 
  doc, 
  updateDoc, 
  deleteDoc, 
  onSnapshot, 
  query, 
  orderBy, 
  getDocs, 
  writeBatch, 
  deleteField, 
  limit, 
  getDoc, 
  where, 
  increment,
  runTransaction 
} from "firebase/firestore";

const ORDER_KEY = 'ecogo_orders_v3'; 
const PRODUCT_KEY = 'ecogo_products_v1';
const CUSTOMER_KEY = 'ecogo_customers_v1';
const USER_KEY = 'ecogo_current_user';
const BANK_KEY = 'ecogo_bank_config';
const SHOP_KEY = 'ecogo_shop_config';
const NOTIF_KEY = 'ecogo_notifications_v1';
const TAGS_KEY = 'ecogo_quick_tags';
const QUOTA_KEY = 'ecogo_quota_status';
const LOGO_KEY = 'ecogo_company_logo';

// --- QUOTA & ONLINE CHECK ---
const checkQuotaStatus = () => {
    try {
        const stored = localStorage.getItem(QUOTA_KEY);
        if (stored) {
            const { date, exhausted } = JSON.parse(stored);
            const today = new Date().toDateString();
            if (date === today && exhausted) return true;
        }
    } catch {}
    return false;
};

let _quotaExhausted = checkQuotaStatus();
const markQuotaExhausted = () => {
    if (!_quotaExhausted) {
        _quotaExhausted = true;
        localStorage.setItem(QUOTA_KEY, JSON.stringify({ date: new Date().toDateString(), exhausted: true }));
        window.dispatchEvent(new Event('quota_exhausted'));
    }
};

const isOnline = () => !!db && !_quotaExhausted;
const isQuotaError = (e: any): boolean => {
    const msg = (e?.message || '').toLowerCase();
    return e?.code === 'resource-exhausted' || msg.includes('quota');
};

// --- IN-MEMORY CACHE ---
let _memoryCustomers: Customer[] | null = null;
let _memoryOrders: Order[] | null = null;
let _memoryProducts: Product[] | null = null;

const ensureCustomersLoaded = () => {
    if (_memoryCustomers) return _memoryCustomers;
    const local = localStorage.getItem(CUSTOMER_KEY);
    _memoryCustomers = local ? JSON.parse(local) : [];
    return _memoryCustomers!;
};

const ensureOrdersLoaded = () => {
    if (_memoryOrders) return _memoryOrders;
    const local = localStorage.getItem(ORDER_KEY);
    _memoryOrders = local ? JSON.parse(local) : [];
    return _memoryOrders!;
};

const ensureProductsLoaded = () => {
    if (_memoryProducts) return _memoryProducts;
    const local = localStorage.getItem(PRODUCT_KEY);
    _memoryProducts = local ? JSON.parse(local) : [];
    return _memoryProducts!;
};

const safeCloudOp = async (operation: () => Promise<any>) => {
    if (!isOnline()) return;
    try { await operation(); } catch (error: any) {
        if (isQuotaError(error)) markQuotaExhausted();
        else console.warn("Cloud Sync Error:", error.message);
    }
};

const sanitize = <T>(obj: T): T => JSON.parse(JSON.stringify(obj));

export const normalizeString = (str: string): string => {
    if (!str) return "";
    return str.normalize("NFD").replace(/[\u0300-\u036f]/g, "").replace(/đ/g, "d").replace(/Đ/g, "D").replace(/[^a-zA-Z0-9]/g, "").toLowerCase();
};

export const normalizePhone = (phone: string) => {
    if (!phone) return '';
    let p = phone.replace(/[^0-9]/g, '');
    if (p.startsWith('84')) p = '0' + p.slice(2);
    if (p.startsWith('+84')) p = '0' + p.slice(3);
    if (p.length === 9 && !p.startsWith('0')) p = '0' + p;
    return p;
};

export const generateProductSku = (name: string): string => {
    if (!name) return uuidv4();
    const sku = name.normalize("NFD").replace(/[\u0300-\u036f]/g, "").replace(/đ/g, "d").replace(/Đ/g, "D").trim().toUpperCase().replace(/[^A-Z0-9]+/g, "_");
    return sku.length < 2 ? uuidv4() : sku;
};

export const storageService = {
  login: (username: string) => { localStorage.setItem(USER_KEY, username); },
  logout: () => { localStorage.removeItem(USER_KEY); },
  getCurrentUser: (): string | null => localStorage.getItem(USER_KEY),

  // --- LOGO & TAGS ---
  getLogo: () => localStorage.getItem(LOGO_KEY),
  saveLogo: (base64: string) => { localStorage.setItem(LOGO_KEY, base64); window.dispatchEvent(new Event('logo_updated')); },
  getQuickTags: () => { try { return JSON.parse(localStorage.getItem(TAGS_KEY) || '[]'); } catch { return ["Dễ vỡ", "Giao gấp"]; } },
  saveQuickTags: async (tags: string[]) => { localStorage.setItem(TAGS_KEY, JSON.stringify(tags)); await safeCloudOp(() => setDoc(doc(db, "settings", "quickTags"), { tags })); },

  // --- CONFIG ---
  getShopConfig: async () => JSON.parse(localStorage.getItem(SHOP_KEY) || '{"shopName":"EcoGo","hotline":""}'),
  saveShopConfig: async (config: ShopConfig) => { localStorage.setItem(SHOP_KEY, JSON.stringify(config)); await safeCloudOp(() => setDoc(doc(db, "settings", "shopConfig"), sanitize(config))); },
  getBankConfig: async () => JSON.parse(localStorage.getItem(BANK_KEY) || 'null'),
  saveBankConfig: async (config: BankConfig) => { localStorage.setItem(BANK_KEY, JSON.stringify(config)); await safeCloudOp(() => setDoc(doc(db, "settings", "bankConfig"), sanitize(config))); },

  // --- PRODUCTS ---
  subscribeProducts: (callback: (products: Product[]) => void) => {
    const list = ensureProductsLoaded();
    callback(list);
    if (isOnline()) {
        return onSnapshot(collection(db, "products"), (snap) => {
            const cloudProds: Product[] = [];
            snap.forEach(d => cloudProds.push(d.data() as Product));
            if (cloudProds.length > 0) {
                _memoryProducts = cloudProds;
                localStorage.setItem(PRODUCT_KEY, JSON.stringify(cloudProds));
                callback(cloudProds);
            }
        });
    }
  },

  saveProduct: async (product: Product) => {
      const pSave = { ...product, updatedAt: Date.now() };
      const list = ensureProductsLoaded();
      const idx = list.findIndex(p => p.id === pSave.id);
      if (idx >= 0) list[idx] = pSave; else list.push(pSave);
      localStorage.setItem(PRODUCT_KEY, JSON.stringify(list));
      window.dispatchEvent(new Event('storage_' + PRODUCT_KEY));
      await safeCloudOp(() => setDoc(doc(db, "products", pSave.id), sanitize(pSave)));
  },

  adjustStockAtomic: async (productId: string, delta: number, importInfo?: any) => {
      const products = ensureProductsLoaded();
      const p = products.find(x => x.id === productId);
      if (p) {
          p.stockQuantity = (p.stockQuantity || 0) + delta;
          if (delta > 0) p.totalImported = (p.totalImported || 0) + delta;
          localStorage.setItem(PRODUCT_KEY, JSON.stringify(products));
      }
      await safeCloudOp(async () => {
          await runTransaction(db, async (tx) => {
              const ref = doc(db, "products", productId);
              const snap = await tx.get(ref);
              if (snap.exists()) {
                  const updates: any = { stockQuantity: increment(delta), updatedAt: Date.now() };
                  if (delta > 0) updates.totalImported = increment(delta);
                  tx.update(ref, updates);
              }
          });
      });
  },

  // --- CUSTOMERS ---
  subscribeCustomers: (callback: (customers: Customer[]) => void) => {
      const list = ensureCustomersLoaded();
      callback(list);
      if (isOnline()) {
          return onSnapshot(collection(db, "customers"), (snap) => {
              const items: Customer[] = [];
              snap.forEach(d => items.push(d.data() as Customer));
              if (items.length > 0) {
                  _memoryCustomers = items;
                  localStorage.setItem(CUSTOMER_KEY, JSON.stringify(items));
                  callback(items);
              }
          });
      }
  },

  upsertCustomer: async (customer: Customer) => {
      const list = ensureCustomersLoaded();
      const idx = list.findIndex(c => c.id === customer.id);
      const cSave = { ...customer, updatedAt: Date.now() };
      if (idx >= 0) list[idx] = cSave; else list.push(cSave);
      localStorage.setItem(CUSTOMER_KEY, JSON.stringify(list));
      await safeCloudOp(() => setDoc(doc(db, "customers", cSave.id), sanitize(cSave)));
  },

  // --- ORDERS CORE (REFACTORED FOR ATOMICITY) ---
  subscribeOrders: (callback: (orders: Order[]) => void) => {
    const list = ensureOrdersLoaded();
    callback(list);
    if (isOnline()) {
        const q = query(collection(db, "orders"), orderBy("createdAt", "desc"), limit(400));
        return onSnapshot(q, (snap) => {
            const fetched: Order[] = [];
            snap.forEach(d => fetched.push(d.data() as Order));
            _memoryOrders = fetched;
            localStorage.setItem(ORDER_KEY, JSON.stringify(fetched));
            callback(fetched);
        });
    }
  },

  saveOrder: async (order: Order) => {
    const now = Date.now();
    const orderWithMeta = { ...order, lastUpdatedBy: storageService.getCurrentUser() || 'System', updatedAt: now };

    // 1. Local Update (Optimistic)
    const list = ensureOrdersLoaded();
    list.unshift(orderWithMeta);
    localStorage.setItem(ORDER_KEY, JSON.stringify(list));

    const prods = ensureProductsLoaded();
    order.items.forEach(it => {
        if (it.productId) {
            const p = prods.find(x => x.id === it.productId);
            if (p) p.stockQuantity = (p.stockQuantity || 0) - it.quantity;
        }
    });
    localStorage.setItem(PRODUCT_KEY, JSON.stringify(prods));

    // 2. Cloud Atomic Transaction
    await safeCloudOp(async () => {
        await runTransaction(db, async (tx) => {
            for (const it of order.items) {
                if (it.productId) {
                    const pRef = doc(db, "products", it.productId);
                    tx.update(pRef, { stockQuantity: increment(-it.quantity), updatedAt: now });
                }
            }
            tx.set(doc(db, "orders", order.id), sanitize(orderWithMeta));
        });
    });
  },

  /**
   * ATOMIC DELETE: Xóa đơn và hoàn kho trong 1 transaction duy nhất
   */
  deleteOrder: async (id: string) => {
      const orders = ensureOrdersLoaded();
      const order = orders.find(o => o.id === id);
      if (!order) return;

      const now = Date.now();

      // 1. Local Optimistic Update
      const newOrders = orders.filter(o => o.id !== id);
      _memoryOrders = newOrders;
      localStorage.setItem(ORDER_KEY, JSON.stringify(newOrders));

      // Chỉ hoàn kho nếu đơn hàng chưa bị Hủy (để tránh hoàn 2 lần nếu status đã là CANCELLED)
      if (order.status !== OrderStatus.CANCELLED) {
          const prods = ensureProductsLoaded();
          order.items.forEach(it => {
              if (it.productId) {
                  const p = prods.find(x => x.id === it.productId);
                  if (p) p.stockQuantity = (p.stockQuantity || 0) + it.quantity;
              }
          });
          localStorage.setItem(PRODUCT_KEY, JSON.stringify(prods));
      }

      // 2. Cloud Atomic Delete + Stock Restore
      await safeCloudOp(async () => {
          await runTransaction(db, async (tx) => {
              const orderRef = doc(db, "orders", id);
              if (order.status !== OrderStatus.CANCELLED) {
                  for (const it of order.items) {
                      if (it.productId) {
                          const pRef = doc(db, "products", it.productId);
                          tx.update(pRef, { stockQuantity: increment(it.quantity), updatedAt: now });
                      }
                  }
              }
              tx.delete(orderRef);
          });
      });
  },

  updateStatus: async (id: string, status: OrderStatus) => {
    const orders = ensureOrdersLoaded();
    const idx = orders.findIndex(o => o.id === id);
    if (idx === -1) return;

    const oldOrder = orders[idx];
    const now = Date.now();

    // LOGIC: Nếu chuyển sang CANCELLED -> Hoàn kho. 
    // Nếu chuyển từ CANCELLED sang trạng thái khác -> Trừ kho.
    let stockDelta = 0;
    if (status === OrderStatus.CANCELLED && oldOrder.status !== OrderStatus.CANCELLED) {
        stockDelta = 1; // Hoàn kho (+)
    } else if (oldOrder.status === OrderStatus.CANCELLED && status !== OrderStatus.CANCELLED) {
        stockDelta = -1; // Trừ kho (-)
    }

    // 1. Local Update
    const updated = { ...oldOrder, status, updatedAt: now, lastUpdatedBy: storageService.getCurrentUser() || 'System' };
    orders[idx] = updated;
    localStorage.setItem(ORDER_KEY, JSON.stringify(orders));

    if (stockDelta !== 0) {
        const prods = ensureProductsLoaded();
        oldOrder.items.forEach(it => {
            if (it.productId) {
                const p = prods.find(x => x.id === it.productId);
                if (p) p.stockQuantity = (p.stockQuantity || 0) + (it.quantity * stockDelta);
            }
        });
        localStorage.setItem(PRODUCT_KEY, JSON.stringify(prods));
    }

    // 2. Cloud Sync
    await safeCloudOp(async () => {
        await runTransaction(db, async (tx) => {
            if (stockDelta !== 0) {
                for (const it of oldOrder.items) {
                    if (it.productId) {
                        tx.update(doc(db, "products", it.productId), { 
                            stockQuantity: increment(it.quantity * stockDelta), 
                            updatedAt: now 
                        });
                    }
                }
            }
            tx.update(doc(db, "orders", id), { status, updatedAt: now, lastUpdatedBy: updated.lastUpdatedBy });
        });
    });
  },

  updateOrderDetails: async (order: Order) => {
    const now = Date.now();
    const orders = ensureOrdersLoaded();
    const idx = orders.findIndex(o => o.id === order.id);
    if (idx === -1) return;

    const oldOrder = orders[idx];
    const productDeltas = new Map<string, number>();

    // Tính toán chênh lệch tồn kho
    if (oldOrder.status !== OrderStatus.CANCELLED) {
        oldOrder.items.forEach(it => { if(it.productId) productDeltas.set(it.productId, (productDeltas.get(it.productId) || 0) + it.quantity); });
    }
    if (order.status !== OrderStatus.CANCELLED) {
        order.items.forEach(it => { if(it.productId) productDeltas.set(it.productId, (productDeltas.get(it.productId) || 0) - it.quantity); });
    }

    // 1. Local update
    orders[idx] = { ...order, updatedAt: now };
    localStorage.setItem(ORDER_KEY, JSON.stringify(orders));

    const prods = ensureProductsLoaded();
    productDeltas.forEach((delta, pid) => {
        const p = prods.find(x => x.id === pid);
        if (p) p.stockQuantity = (p.stockQuantity || 0) + delta;
    });
    localStorage.setItem(PRODUCT_KEY, JSON.stringify(prods));

    // 2. Cloud Transaction
    await safeCloudOp(async () => {
        await runTransaction(db, async (tx) => {
            for (const [pid, delta] of productDeltas.entries()) {
                if (Math.abs(delta) > 0) {
                    tx.update(doc(db, "products", pid), { stockQuantity: increment(delta), updatedAt: now });
                }
            }
            tx.set(doc(db, "orders", order.id), sanitize({ ...order, updatedAt: now }));
        });
    });
  },

  updatePaymentVerification: async (id: string, verified: boolean) => {
      await safeCloudOp(() => updateDoc(doc(db, "orders", id), { paymentVerified: verified, updatedAt: Date.now() }));
  },

  deleteOrdersBatch: async (ids: string[]) => {
      for (const id of ids) { await storageService.deleteOrder(id); }
  },

  moveOrdersBatch: async (ids: string[], targetBatch: string) => {
      const batch = writeBatch(db);
      ids.forEach(id => batch.update(doc(db, "orders", id), { batchId: targetBatch, updatedAt: Date.now() }));
      await safeCloudOp(() => batch.commit());
  },

  // --- TOOLS ---
  recalculateInventoryFromOrders: async () => {
      const prods = ensureProductsLoaded();
      const orders = ensureOrdersLoaded();
      const soldMap = new Map<string, number>();

      orders.filter(o => o.status !== OrderStatus.CANCELLED).forEach(o => {
          o.items.forEach(it => {
              if (it.productId) soldMap.set(it.productId, (soldMap.get(it.productId) || 0) + it.quantity);
          });
      });

      prods.forEach(p => {
          const totalSold = soldMap.get(p.id) || 0;
          const totalImported = p.totalImported || (p.stockQuantity + totalSold);
          p.stockQuantity = Math.max(0, totalImported - totalSold);
          p.totalImported = totalImported;
      });

      localStorage.setItem(PRODUCT_KEY, JSON.stringify(prods));
      for (const p of prods) { await storageService.saveProduct(p); }
      return prods.length;
  },

  subscribeNotifications: (cb: (n: Notification[]) => void) => {
      if (isOnline()) {
          return onSnapshot(query(collection(db, "notifications"), orderBy('createdAt', 'desc'), limit(40)), (snap) => {
              const list: Notification[] = [];
              snap.forEach(d => list.push(d.data() as Notification));
              cb(list);
          });
      }
  }
};

import React, { useEffect, useState, useMemo, useRef, useDeferredValue, useCallback } from 'react';
import toast from 'react-hot-toast';
import { Order, OrderStatus, PaymentMethod, OrderItem, Product, Customer, ShopConfig, BankConfig, CarrierData } from '../types';
import { storageService, normalizePhone, normalizeString } from '../services/storageService';
import { pdfService } from '../services/pdfService';
import { OrderCard } from './OrderCard';
import ConfirmModal from './ConfirmModal';
import RoutePlannerModal from './RoutePlannerModal'; 
import ShipmentModal from './ShipmentModal';
import { ProductDetailModal, ProductEditModal } from './InventoryManager';

type SortOption = 'NEWEST' | 'ROUTE' | 'STATUS';

const TrackingDashboard: React.FC = () => {
  const [orders, setOrders] = useState<Order[]>([]);
  const [products, setProducts] = useState<Product[]>([]); 
  const [customers, setCustomers] = useState<Customer[]>([]);
  const [filterStatus, setFilterStatus] = useState<OrderStatus[]>([]);
  const [filterBatch, setFilterBatch] = useState<string[]>([]);
  const [searchTerm, setSearchTerm] = useState('');
  const deferredSearchTerm = useDeferredValue(searchTerm);
  const [sortBy, setSortBy] = useState<SortOption>('NEWEST');
  const [isCompactMode, setIsCompactMode] = useState(false); 
  const [editingOrder, setEditingOrder] = useState<Order | null>(null);
  const [showDeleteConfirm, setShowDeleteConfirm] = useState(false);
  const [deleteId, setDeleteId] = useState<string | null>(null);
  const [isSelectionMode, setIsSelectionMode] = useState(false);
  const [selectedOrderIds, setSelectedOrderIds] = useState<Set<string>>(new Set());
  const [showBulkDeleteConfirm, setShowBulkDeleteConfirm] = useState(false);
  const [showBulkStatusModal, setShowBulkStatusModal] = useState(false);
  const [detailOrder, setDetailOrder] = useState<Order | null>(null);
  const [showRoutePlanner, setShowRoutePlanner] = useState(false);
  const [shipmentOrder, setShipmentOrder] = useState<Order | null>(null);
  const [showShipmentModal, setShowShipmentModal] = useState(false);

  useEffect(() => {
    const unsubOrders = storageService.subscribeOrders(setOrders);
    const unsubProducts = storageService.subscribeProducts(setProducts);
    const unsubCustomers = storageService.subscribeCustomers(setCustomers);
    return () => { 
        if (unsubOrders) unsubOrders(); 
        if (unsubProducts) unsubProducts();
        if (unsubCustomers) unsubCustomers(); 
    };
  }, []);

  const handleDeleteClick = (id: string) => { setDeleteId(id); setShowDeleteConfirm(true); };

  /**
   * REFACTORED:confirmDelete hiện tại cực kỳ tinh gọn.
   * Toàn bộ logic hoàn kho đã được đóng gói an toàn trong Service (Atomic).
   */
  const confirmDelete = async () => {
    if (deleteId) {
      const toastId = toast.loading("Đang xóa đơn và hoàn kho...");
      try {
        await storageService.deleteOrder(deleteId);
        toast.success('Đã xóa đơn & Tồn kho đã tự động cập nhật!', { id: toastId });
        setShowDeleteConfirm(false);
        setDeleteId(null);
        if(detailOrder?.id === deleteId) setDetailOrder(null);
      } catch (e) {
        toast.error("Lỗi khi xóa đơn hàng");
      }
    }
  };

  const executeBulkDelete = async () => {
    if (selectedOrderIds.size === 0) return;
    const ids = Array.from(selectedOrderIds);
    const toastId = toast.loading(`Đang xóa ${ids.length} đơn...`);
    try {
        await storageService.deleteOrdersBatch(ids);
        toast.success(`Đã xóa xong & Hoàn kho tất cả!`, { id: toastId });
        setSelectedOrderIds(new Set());
        setIsSelectionMode(false);
        setShowBulkDeleteConfirm(false);
    } catch (e) {
        toast.error("Lỗi xóa hàng loạt");
    }
  };

  const filteredOrders = useMemo(() => {
    let result = orders.filter(o => {
      const statusMatch = filterStatus.length === 0 || filterStatus.includes(o.status);
      const batchMatch = filterBatch.length === 0 || (o.batchId && filterBatch.includes(o.batchId));
      if (!statusMatch || !batchMatch) return false;
      if (!deferredSearchTerm) return true;
      const term = normalizeString(deferredSearchTerm);
      return normalizeString(o.customerName).includes(term) || normalizePhone(o.customerPhone).includes(term);
    });
    return result.sort((a, b) => b.createdAt - a.createdAt);
  }, [orders, filterStatus, filterBatch, deferredSearchTerm]);

  return (
    <div className="animate-fade-in pb-32">
      {/* Header Filters */}
      <div className="bg-white p-4 rounded-2xl shadow-sm border border-gray-100 mb-6 sticky top-16 z-30">
          <div className="flex gap-2">
              <input 
                placeholder="Tìm khách hàng..." 
                value={searchTerm} 
                onChange={e => setSearchTerm(e.target.value)}
                className="flex-grow p-2 bg-gray-50 rounded-xl outline-none focus:ring-2 focus:ring-eco-200"
              />
              <button onClick={() => setShowRoutePlanner(true)} className="bg-blue-600 text-white px-4 py-2 rounded-xl font-bold text-xs">Sắp xếp Lộ trình</button>
          </div>
      </div>

      {/* List */}
      <div className="grid grid-cols-1 md:grid-cols-2 xl:grid-cols-3 gap-4">
        {filteredOrders.map((order, idx) => (
            <OrderCard 
                key={order.id}
                order={order}
                onDelete={handleDeleteClick}
                onEdit={(o) => setEditingOrder(o)}
                onUpdate={() => {}}
                onViewDetail={(o) => setDetailOrder(o)}
                index={idx}
                isSelectionMode={isSelectionMode}
                isSelected={selectedOrderIds.has(order.id)}
                onToggleSelect={(id) => {
                    const newSet = new Set(selectedOrderIds);
                    if(newSet.has(id)) newSet.delete(id); else newSet.add(id);
                    setSelectedOrderIds(newSet);
                    setIsSelectionMode(newSet.size > 0);
                }}
            />
        ))}
      </div>

      {/* Bulk Action Bar */}
      {isSelectionMode && (
          <div className="fixed bottom-10 left-1/2 -translate-x-1/2 bg-black text-white px-6 py-4 rounded-2xl shadow-2xl flex items-center gap-6 z-50 animate-bounce-in">
              <span className="font-bold">Đã chọn {selectedOrderIds.size}</span>
              <button onClick={() => setShowBulkDeleteConfirm(true)} className="text-red-400 font-bold hover:text-red-300">Xóa hết</button>
              <button onClick={() => setIsSelectionMode(false)} className="text-gray-400">Hủy</button>
          </div>
      )}

      {/* Modals */}
      <ConfirmModal 
        isOpen={showDeleteConfirm} 
        title="Xóa đơn hàng?" 
        message="Hệ thống sẽ tự động hoàn trả số lượng hàng vào kho sau khi xóa." 
        onConfirm={confirmDelete} 
        onCancel={() => setShowDeleteConfirm(false)} 
        isDanger={true} 
      />

      <ConfirmModal 
        isOpen={showBulkDeleteConfirm} 
        title={`Xóa ${selectedOrderIds.size} đơn?`} 
        message="Hành động này sẽ xóa vĩnh viễn các đơn đã chọn và hoàn kho tự động." 
        onConfirm={executeBulkDelete} 
        onCancel={() => setShowBulkDeleteConfirm(false)} 
        isDanger={true} 
      />

      <RoutePlannerModal isOpen={showRoutePlanner} onClose={() => setShowRoutePlanner(false)} orders={filteredOrders} onApplySort={() => {}} />
    </div>
  );
};

export default TrackingDashboard;

import { Order } from '../types';
import { normalizeString } from './storageService';

export interface RouteZone {
    id: string;
    name: string;
    priority: number;
    keywords: string[];
}

export const ROUTE_ZONES: RouteZone[] = [
    { id: 'ECO_XUAN', name: '1. Eco Xuân', priority: 10, keywords: ['eco xuan', 'eco xuân', 'block a', 'block b', 'block c'] },
    { id: 'EHOME_4', name: '2. Ehome 4', priority: 20, keywords: ['ehome 4', 'vĩnh phú 41', 'khu bắc'] },
    { id: 'LAI_THIEU', name: '3. Lái Thiêu', priority: 30, keywords: ['lái thiêu', 'lt115', 'lt117'] },
    { id: 'OTHER', name: '4. Khác', priority: 999, keywords: [] }
];

export const routeService = {
    identifyZone: (address: string): RouteZone => {
        const addr = normalizeString(address || "");
        for (const zone of ROUTE_ZONES) {
            if (zone.keywords.some(k => addr.includes(normalizeString(k)))) return zone;
        }
        return ROUTE_ZONES[ROUTE_ZONES.length - 1];
    },

    sortOrdersByRoute: (orders: Order[]): Order[] => {
        return [...orders].sort((a, b) => {
            const zA = routeService.identifyZone(a.address);
            const zB = routeService.identifyZone(b.address);
            if (zA.priority !== zB.priority) return zA.priority - zB.priority;
            return a.address.localeCompare(b.address);
        });
    },

    groupOrdersByZone: (orders: Order[]) => {
        const sorted = routeService.sortOrdersByRoute(orders);
        const groups: Record<string, { name: string, orders: Order[] }> = {};
        sorted.forEach(o => {
            const zone = routeService.identifyZone(o.address);
            if (!groups[zone.id]) groups[zone.id] = { name: zone.name, orders: [] };
            groups[zone.id].orders.push(o);
        });
        return Object.values(groups);
    },

    generateRouteText: (orders: Order[]) => {
        const groups = routeService.groupOrdersByZone(orders);
        let text = `🚀 LỘ TRÌNH GIAO HÀNG (${new Date().toLocaleDateString('vi-VN')})\n\n`;
        groups.forEach(g => {
            text += `📍 ${g.name.toUpperCase()}\n`;
            g.orders.forEach((o, idx) => {
                text += `${idx + 1}. ${o.customerName} - ${o.address}\n`;
            });
            text += `----------------\n`;
        });
        return text;
    }
};

