  // Fix: Add syncProductToPendingOrders method
  syncProductToPendingOrders: async (product: Product) => {
      const orders = ensureOrdersLoaded();
      let count = 0;
      orders.forEach(o => {
          if (o.status === OrderStatus.PENDING || o.status === OrderStatus.PICKED_UP) {
              let changed = false;
              o.items.forEach(it => {
                  if (it.productId === product.id) {
                      it.name = product.name;
                      it.price = product.defaultPrice;
                      it.importPrice = product.importPrice;
                      changed = true;
                  }
              });
              if (changed) count++;
          }
      });
      if (count > 0) {
          localStorage.setItem(ORDER_KEY, JSON.stringify(orders));
          await safeCloudOp(async () => {
              const batch = writeBatch(db);
              orders.forEach(o => {
                  if (o.status === OrderStatus.PENDING || o.status === OrderStatus.PICKED_UP) {
                      batch.update(doc(db, "orders", o.id), { items: o.items, updatedAt: Date.now() });
                  }
              });
              await batch.commit();
          });
      }
      return count;
  },

  // Fix: Add cleanAndMergeDuplicateProducts method
  cleanAndMergeDuplicateProducts: async () => {
      const prods = ensureProductsLoaded();
      const nameMap = new Map<string, Product[]>();
      prods.forEach(p => {
          const norm = normalizeString(p.name);
          if (!nameMap.has(norm)) nameMap.set(norm, []);
          nameMap.get(norm)!.push(p);
      });

      let mergedCount = 0;
      let fixedOrders = 0;

      for (const group of nameMap.values()) {
          if (group.length > 1) {
              const master = group[0];
              const duplicates = group.slice(1);

              duplicates.forEach(dup => {
                  master.stockQuantity += dup.stockQuantity;
                  master.totalImported = (master.totalImported || 0) + (dup.totalImported || 0);
                  const orders = ensureOrdersLoaded();
                  orders.forEach(o => {
                      o.items.forEach(it => {
                          if (it.productId === dup.id) {
                              it.productId = master.id;
                              fixedOrders++;
                          }
                      });
                  });
              });

              for(const dup of duplicates) {
                  await storageService.deleteProduct(dup.id);
              }
              await storageService.saveProduct(master);
              mergedCount += duplicates.length;
          }
      }
      return { mergedCount, fixedOrders };
  },

