      for (const id of ids) { await storageService.deleteOrder(id); }
  },

  moveOrdersBatch: async (ids: string[], targetBatch: string) => {
      const batch = writeBatch(db);
      ids.forEach(id => batch.update(doc(db, "orders", id), { batchId: targetBatch, updatedAt: Date.now() }));
      await safeCloudOp(() => batch.commit());
  },

  // --- TOOLS ---
  recalculateInventoryFromOrders: async () => {
      const prods = ensureProductsLoaded();
      const orders = ensureOrdersLoaded();
      const soldMap = new Map<string, number>();

      orders.filter(o => o.status !== OrderStatus.CANCELLED).forEach(o => {
          o.items.forEach(it => {
              if (it.productId) soldMap.set(it.productId, (soldMap.get(it.productId) || 0) + it.quantity);
          });
      });

      prods.forEach(p => {
          const totalSold = soldMap.get(p.id) || 0;
          const totalImported = p.totalImported || (p.stockQuantity + totalSold);
          p.stockQuantity = Math.max(0, totalImported - totalSold);
          p.totalImported = totalImported;
      });

      localStorage.setItem(PRODUCT_KEY, JSON.stringify(prods));
      for (const p of prods) { await storageService.saveProduct(p); }
      return prods.length;
  },

  // Fix: Add fetchLongTermStats method
  fetchLongTermStats: async () => {
      if (isOnline()) {
          const snap = await getDocs(collection(db, "orders"));
          const items: Order[] = [];
          snap.forEach(d => items.push(d.data() as Order));
          return items;
      }
      return ensureOrdersLoaded();
  },

  // Fix: Add syncLocalToCloud method
  syncLocalToCloud: async () => {
      const orders = ensureOrdersLoaded();
      const products = ensureProductsLoaded();
      const customers = ensureCustomersLoaded();

      await safeCloudOp(async () => {
          const batch = writeBatch(db);
          orders.forEach(o => batch.set(doc(db, "orders", o.id), sanitize(o)));
          products.forEach(p => batch.set(doc(db, "products", p.id), sanitize(p)));
          customers.forEach(c => batch.set(doc(db, "customers", c.id), sanitize(c)));
          await batch.commit();
      });
      return orders.length;
  },

  // Fix: Add developer/test methods
  generatePerformanceData: async (count: number) => {
      const start = Date.now();
      const newCustomers: Customer[] = [];
      for (let i = 0; i < count; i++) {
          newCustomers.push({
              id: uuidv4(),
              name: `Stress Test ${i}`,
              phone: `09${Math.floor(Math.random() * 90000000 + 10000000)}`,
              address: `${i} Mock Street, Test City`,
              lastOrderDate: Date.now(),
              priorityScore: 999
          });
      }
      await storageService.importCustomersBatch(newCustomers, true);
      return { count, duration: Date.now() - start };
  },

  markAllCustomersAsOld: async () => {
      const list = ensureCustomersLoaded();
      list.forEach(c => c.isLegacy = true);
      localStorage.setItem(CUSTOMER_KEY, JSON.stringify(list));
      await storageService.importCustomersBatch(list, false);
      return list.length;
  },

  fixDuplicateCustomerIds: async () => {
      const list = ensureCustomersLoaded();
      const idMap = new Map<string, number>();
      let fixed = 0;
      list.forEach(c => {
          if (idMap.has(c.id)) {
              c.id = uuidv4();
              fixed++;
          }
          idMap.set(c.id, 1);
      });
      if (fixed > 0) {
          localStorage.setItem(CUSTOMER_KEY, JSON.stringify(list));
          await storageService.importCustomersBatch(list, false);
      }
      return fixed;
  },

  mergeCustomersByPhone: async () => {
      const list = ensureCustomersLoaded();
      const phoneMap = new Map<string, Customer[]>();
      list.forEach(c => {
          if (c.phone && c.phone.length > 5) {
              if (!phoneMap.has(c.phone)) phoneMap.set(c.phone, []);
              phoneMap.get(c.phone)!.push(c);
          }
      });
      let count = 0;
      for (const group of phoneMap.values()) {
          if (group.length > 1) count++;
      }
      return count;
  },

  // --- NOTIFICATIONS ---
  subscribeNotifications: (cb: (n: Notification[]) => void) => {
      if (isOnline()) {
          return onSnapshot(query(collection(db, "notifications"), orderBy('createdAt', 'desc'), limit(40)), (snap) => {
              const list: Notification[] = [];
              snap.forEach(d => list.push(d.data() as Notification));
              cb(list);
          });
      }
  },

  // Fix: Add markNotificationRead method
  markNotificationRead: async (id: string) => {
      await safeCloudOp(() => updateDoc(doc(db, "notifications", id), { isRead: true }));
  },

  // Fix: Add markAllNotificationsRead method
  markAllNotificationsRead: async () => {
      await safeCloudOp(async () => {
          const q = query(collection(db, "notifications"), where("isRead", "==", false));
          const snap = await getDocs(q);
          const batch = writeBatch(db);
          snap.forEach(d => batch.update(d.ref, { isRead: true }));
          await batch.commit();
      });
  },

  // Fix: Add clearAllNotifications method
  clearAllNotifications: async () => {
      await safeCloudOp(async () => {
          const snap = await getDocs(collection(db, "notifications"));
          const batch = writeBatch(db);
          snap.forEach(d => batch.delete(d.ref));
          await batch.commit();
      });
  }
};

import React, { useEffect, useState, useMemo, useRef, useDeferredValue, useCallback } from 'react';
import toast from 'react-hot-toast';
import { Order, OrderStatus, PaymentMethod, OrderItem, Product, Customer, ShopConfig, BankConfig, CarrierData } from '../types';
import { storageService, normalizePhone, normalizeString } from '../services/storageService';
import { pdfService } from '../services/pdfService';
import { OrderCard } from './OrderCard';
import ConfirmModal from './ConfirmModal';
import RoutePlannerModal from './RoutePlannerModal'; 
import ShipmentModal from './ShipmentModal';
import { ProductDetailModal, ProductEditModal } from './InventoryManager';

type SortOption = 'NEWEST' | 'ROUTE' | 'STATUS';

const TrackingDashboard: React.FC = () => {
  const [orders, setOrders] = useState<Order[]>([]);
  const [products, setProducts] = useState<Product[]>([]); 
  const [customers, setCustomers] = useState<Customer[]>([]);
  const [filterStatus, setFilterStatus] = useState<OrderStatus[]>([]);
  const [filterBatch, setFilterBatch] = useState<string[]>([]);
  const [searchTerm, setSearchTerm] = useState('');
  const deferredSearchTerm = useDeferredValue(searchTerm);
  const [sortBy, setSortBy] = useState<SortOption>('NEWEST');
  const [isCompactMode, setIsCompactMode] = useState(false); 
  const [editingOrder, setEditingOrder] = useState<Order | null>(null);
  const [showDeleteConfirm, setShowDeleteConfirm] = useState(false);
  const [deleteId, setDeleteId] = useState<string | null>(null);
  const [isSelectionMode, setIsSelectionMode] = useState(false);
  const [selectedOrderIds, setSelectedOrderIds] = useState<Set<string>>(new Set());
  const [showBulkDeleteConfirm, setShowBulkDeleteConfirm] = useState(false);
  const [showBulkStatusModal, setShowBulkStatusModal] = useState(false);
  const [detailOrder, setDetailOrder] = useState<Order | null>(null);
  const [showRoutePlanner, setShowRoutePlanner] = useState(false);
  const [shipmentOrder, setShipmentOrder] = useState<Order | null>(null);
  const [showShipmentModal, setShowShipmentModal] = useState(false);

  useEffect(() => {
    const unsubOrders = storageService.subscribeOrders(setOrders);
    const unsubProducts = storageService.subscribeProducts(setProducts);
    const unsubCustomers = storageService.subscribeCustomers(setCustomers);
    return () => { 
        if (unsubOrders) unsubOrders(); 
        if (unsubProducts) unsubProducts();
        if (unsubCustomers) unsubCustomers(); 
    };
  }, []);

  const handleDeleteClick = (id: string) => { setDeleteId(id); setShowDeleteConfirm(true); };

  /**
   * REFACTORED:confirmDelete hiện tại cực kỳ tinh gọn.
   * Toàn bộ logic hoàn kho đã được đóng gói an toàn trong Service (Atomic).
   */
  const confirmDelete = async () => {
    if (deleteId) {
      const toastId = toast.loading("Đang xóa đơn và hoàn kho...");
      try {
        await storageService.deleteOrder(deleteId);
        toast.success('Đã xóa đơn & Tồn kho đã tự động cập nhật!', { id: toastId });
        setShowDeleteConfirm(false);
        setDeleteId(null);
        if(detailOrder?.id === deleteId) setDetailOrder(null);
      } catch (e) {
        toast.error("Lỗi khi xóa đơn hàng");
      }
    }
  };

  const executeBulkDelete = async () => {
    if (selectedOrderIds.size === 0) return;
    // Fix: cast to string[] to resolve the Argument of type 'unknown[]' error
    const ids = Array.from(selectedOrderIds) as string[];
    const toastId = toast.loading(`Đang xóa ${ids.length} đơn...`);
    try {
        await storageService.deleteOrdersBatch(ids);
        toast.success(`Đã xóa xong & Hoàn kho tất cả!`, { id: toastId });
        setSelectedOrderIds(new Set());
        setIsSelectionMode(false);
        setShowBulkDeleteConfirm(false);
    } catch (e) {
        toast.error("Lỗi xóa hàng loạt");
    }
  };

  const filteredOrders = useMemo(() => {
    let result = orders.filter(o => {
      const statusMatch = filterStatus.length === 0 || filterStatus.includes(o.status);
      const batchMatch = filterBatch.length === 0 || (o.batchId && filterBatch.includes(o.batchId));
      if (!statusMatch || !batchMatch) return false;
      if (!deferredSearchTerm) return true;
      const term = normalizeString(deferredSearchTerm);
      return normalizeString(o.customerName).includes(term) || normalizePhone(o.customerPhone).includes(term);
    });
    return result.sort((a, b) => b.createdAt - a.createdAt);
  }, [orders, filterStatus, filterBatch, deferredSearchTerm]);

  return (
    <div className="animate-fade-in pb-32">
      {/* Header Filters */}
      <div className="bg-white p-4 rounded-2xl shadow-sm border border-gray-100 mb-6 sticky top-16 z-30">
          <div className="flex gap-2">
              <input 
                placeholder="Tìm khách hàng..." 
                value={searchTerm} 
                onChange={e => setSearchTerm(e.target.value)}
                className="flex-grow p-2 bg-gray-50 rounded-xl outline-none focus:ring-2 focus:ring-eco-200"
              />
              <button onClick={() => setShowRoutePlanner(true)} className="bg-blue-600 text-white px-4 py-2 rounded-xl font-bold text-xs">Sắp xếp Lộ trình</button>
          </div>
      </div>

      {/* List */}
      <div className="grid grid-cols-1 md:grid-cols-2 xl:grid-cols-3 gap-4">
        {filteredOrders.map((order, idx) => (
            <OrderCard 
                key={order.id}
                order={order}
                onDelete={handleDeleteClick}
                onEdit={(o) => setEditingOrder(o)}
                onUpdate={() => {}}
                onViewDetail={(o) => setDetailOrder(o)}
                index={idx}
                isSelectionMode={isSelectionMode}
                isSelected={selectedOrderIds.has(order.id)}
                onToggleSelect={(id) => {
                    const newSet = new Set(selectedOrderIds);
                    if(newSet.has(id)) newSet.delete(id); else newSet.add(id);
                    setSelectedOrderIds(newSet);
                    setIsSelectionMode(newSet.size > 0);
                }}
            />
        ))}
      </div>

      {/* Bulk Action Bar */}
      {isSelectionMode && (
          <div className="fixed bottom-10 left-1/2 -translate-x-1/2 bg-black text-white px-6 py-4 rounded-2xl shadow-2xl flex items-center gap-6 z-50 animate-bounce-in">
              <span className="font-bold">Đã chọn {selectedOrderIds.size}</span>
              <button onClick={() => setShowBulkDeleteConfirm(true)} className="text-red-400 font-bold hover:text-red-300">Xóa hết</button>
              <button onClick={() => setIsSelectionMode(false)} className="text-gray-400">Hủy</button>
          </div>
      )}

      {/* Modals */}
      <ConfirmModal 
        isOpen={showDeleteConfirm} 
        title="Xóa đơn hàng?" 
        message="Hệ thống sẽ tự động hoàn trả số lượng hàng vào kho sau khi xóa." 
        onConfirm={confirmDelete} 
        onCancel={() => setShowDeleteConfirm(false)} 
        isDanger={true} 
      />

      <ConfirmModal 
        isOpen={showBulkDeleteConfirm} 
        title={`Xóa ${selectedOrderIds.size} đơn?`} 
        message="Hành động này sẽ xóa vĩnh viễn các đơn đã chọn và hoàn kho tự động." 
        onConfirm={executeBulkDelete} 
        onCancel={() => setShowBulkDeleteConfirm(false)} 
        isDanger={true} 
      />

      <RoutePlannerModal isOpen={showRoutePlanner} onClose={() => setShowRoutePlanner(false)} orders={filteredOrders} onApplySort={() => {}} />
    </div>
  );
};

