import React, { useEffect, useState, useMemo, useRef, useDeferredValue, useCallback } from 'react';
import toast from 'react-hot-toast';
import { Order, OrderStatus, PaymentMethod, OrderItem, Product, Customer, ShopConfig, BankConfig, CarrierData } from '../types';
import { storageService, normalizePhone, normalizeString } from '../services/storageService';
import { pdfService } from '../services/pdfService';
import { OrderCard } from './OrderCard';
import ConfirmModal from './ConfirmModal';
import RoutePlannerModal from './RoutePlannerModal'; 
import ShipmentModal from './ShipmentModal';
import { ProductDetailModal, ProductEditModal } from './InventoryManager';
import QRCode from 'qrcode';

type SortOption = 'NEWEST' | 'ROUTE' | 'STATUS';

const TrackingDashboard: React.FC = () => {
  // --- DATA STATE ---
  const [orders, setOrders] = useState<Order[]>([]);
  const [products, setProducts] = useState<Product[]>([]); 
  const [customers, setCustomers] = useState<Customer[]>([]);
  const [bankConfig, setBankConfig] = useState<BankConfig | null>(null);

  // --- UI STATE ---
  const [filterStatus, setFilterStatus] = useState<OrderStatus[]>([]);
  const [filterBatch, setFilterBatch] = useState<string[]>([]);
  const [searchTerm, setSearchTerm] = useState('');
  const deferredSearchTerm = useDeferredValue(searchTerm);
  const [sortBy, setSortBy] = useState<SortOption>('NEWEST');
  const [isCompactMode, setIsCompactMode] = useState(false); 

  // --- SELECTION & BULK ---
  const [isSelectionMode, setIsSelectionMode] = useState(false);
  const [selectedOrderIds, setSelectedOrderIds] = useState<Set<string>>(new Set());
  const [showBulkDeleteConfirm, setShowBulkDeleteConfirm] = useState(false);
  const [showBulkBatchModal, setShowBulkBatchModal] = useState(false);
  const [targetBatch, setTargetBatch] = useState('');

  // --- MODALS STATE ---
  const [editingOrder, setEditingOrder] = useState<Order | null>(null);
  const [detailOrder, setDetailOrder] = useState<Order | null>(null);
  const [showDeleteConfirm, setShowDeleteConfirm] = useState(false);
  const [deleteId, setDeleteId] = useState<string | null>(null);
  const [showRoutePlanner, setShowRoutePlanner] = useState(false);
  const [shipmentOrder, setShipmentOrder] = useState<Order | null>(null);
  const [showShipmentModal, setShowShipmentModal] = useState(false);

  // QR State
  const [qrModal, setQrModal] = useState<{ isOpen: boolean, url: string, orderId: string } | null>(null);

  useEffect(() => {
    const unsubOrders = storageService.subscribeOrders(setOrders);
    const unsubProducts = storageService.subscribeProducts(setProducts);
    const unsubCustomers = storageService.subscribeCustomers(setCustomers);
    storageService.getBankConfig().then(setBankConfig);

    return () => { 
        if (unsubOrders) unsubOrders(); 
        if (unsubProducts) unsubProducts();
        if (unsubCustomers) unsubCustomers(); 
    };
  }, []);

  // --- BATCH LIST FOR FILTER ---
  const allBatches = useMemo(() => {
    const batches = new Set<string>();
    orders.forEach(o => { if (o.batchId) batches.add(o.batchId); });
    return Array.from(batches).sort();
  }, [orders]);

  // --- FILTER & SORT LOGIC ---
  const filteredOrders = useMemo(() => {
    let result = orders.filter(o => {
      const statusMatch = filterStatus.length === 0 || filterStatus.includes(o.status);
      const batchMatch = filterBatch.length === 0 || (o.batchId && filterBatch.includes(o.batchId));
      if (!statusMatch || !batchMatch) return false;
      if (!deferredSearchTerm) return true;
      const term = normalizeString(deferredSearchTerm);
      return normalizeString(o.customerName).includes(term) || normalizePhone(o.customerPhone).includes(term) || o.id.toLowerCase().includes(term);
    });

    if (sortBy === 'NEWEST') return result.sort((a, b) => b.createdAt - a.createdAt);
    return result;
  }, [orders, filterStatus, filterBatch, deferredSearchTerm, sortBy]);

  // --- ACTIONS ---
  const handleDeleteClick = (id: string) => { setDeleteId(id); setShowDeleteConfirm(true); };

  const confirmDelete = async () => {
    if (deleteId) {
      const toastId = toast.loading("Đang xóa đơn và hoàn kho...");
      try {
        await storageService.deleteOrder(deleteId);
        toast.success('Đã xóa đơn & Hoàn kho tự động!', { id: toastId });
        setShowDeleteConfirm(false);
        setDeleteId(null);
        if(detailOrder?.id === deleteId) setDetailOrder(null);
      } catch (e) {
        toast.error("Lỗi khi xóa đơn hàng");
      }
    }
  };

  const toggleSelect = (id: string) => {
    const newSet = new Set(selectedOrderIds);
    if (newSet.has(id)) newSet.delete(id); else newSet.add(id);
    setSelectedOrderIds(newSet);
    setIsSelectionMode(newSet.size > 0);
  };

  const executeBulkDelete = async () => {
    const ids = Array.from(selectedOrderIds) as string[];
    const toastId = toast.loading(`Đang xóa ${ids.length} đơn...`);
    try {
        await storageService.deleteOrdersBatch(ids);
        toast.success(`Đã xóa & Hoàn kho toàn bộ!`, { id: toastId });
        setSelectedOrderIds(new Set());
        setIsSelectionMode(false);
        setShowBulkDeleteConfirm(false);
    } catch (e) {
        toast.error("Lỗi xóa hàng loạt");
    }
  };

  const handleBulkMoveBatch = async () => {
      if (!targetBatch) return;
      const ids = Array.from(selectedOrderIds) as string[];
      await storageService.moveOrdersBatch(ids, targetBatch);
      toast.success(`Đã chuyển ${ids.length} đơn sang lô ${targetBatch}`);
      setShowBulkBatchModal(false);
      setSelectedOrderIds(new Set());
      setIsSelectionMode(false);
  };

  // --- PDF EXPORT ---
  const exportManifest = async () => {
      if (filteredOrders.length === 0) return toast.error("Không có đơn để in");
      const batchName = filterBatch.length === 1 ? filterBatch[0] : "Tong_Hop";
      toast.promise(pdfService.generateCompactList(filteredOrders, batchName), {
          loading: 'Đang tạo bảng kê...',
          success: 'Đã tải bảng kê PDF!',
          error: 'Lỗi khi tạo PDF'
      });
  };

  const exportInvoices = async () => {
      if (filteredOrders.length === 0) return toast.error("Không có đơn để in");
      const batchName = filterBatch.length === 1 ? filterBatch[0] : "Hoa_Don";
      toast.promise(pdfService.generateInvoiceBatch(filteredOrders, batchName), {
          loading: 'Đang tạo hóa đơn...',
          success: 'Đã tải hóa đơn PDF!',
          error: 'Lỗi khi tạo PDF'
      });
  };

  // --- QR HANDLER ---
  const handleShowQR = async (order: Order) => {
      if (!bankConfig?.accountNo) return toast.error("Chưa cài đặt ngân hàng");
      const qrContent = `DH ${order.id}`;
      // VietQR syntax
      const qrUrl = `https://img.vietqr.io/image/${bankConfig.bankId}-${bankConfig.accountNo}-compact2.png?amount=${order.totalPrice}&addInfo=${encodeURIComponent(qrContent)}&accountName=${encodeURIComponent(bankConfig.accountName)}`;
      setQrModal({ isOpen: true, url: qrUrl, orderId: order.id });
  };

  return (
    <div className="animate-fade-in pb-32">
      {/* 1. FILTER BAR (STICKY) */}
      <div className="bg-white/90 backdrop-blur-md p-4 rounded-2xl shadow-sm border border-gray-100 mb-6 sticky top-16 z-30 space-y-3">
          <div className="flex flex-col md:flex-row gap-3">
              <div className="relative flex-grow">
                  <i className="fas fa-search absolute left-3 top-3 text-gray-400"></i>
                  <input 
                    placeholder="Tìm tên, SĐT, mã đơn..." 
                    value={searchTerm} 
                    onChange={e => setSearchTerm(e.target.value)}
                    className="w-full pl-10 pr-4 py-2.5 bg-gray-50 rounded-xl outline-none focus:ring-2 focus:ring-eco-200 border-transparent focus:border-eco-500 border transition-all font-medium"
                  />
              </div>
              <div className="flex gap-2">
                  <select 
                    value={filterBatch[0] || 'ALL'} 
                    onChange={e => setFilterBatch(e.target.value === 'ALL' ? [] : [e.target.value])}
                    className="bg-gray-50 px-3 py-2 rounded-xl text-sm font-bold border-transparent outline-none focus:ring-2 focus:ring-eco-200"
                  >
                      <option value="ALL">Tất cả Lô</option>
                      {allBatches.map(b => <option key={b} value={b}>{b}</option>)}
                  </select>
                  <button 
                    onClick={() => setIsCompactMode(!isCompactMode)}
                    className={`w-10 h-10 rounded-xl flex items-center justify-center transition-colors ${isCompactMode ? 'bg-eco-600 text-white' : 'bg-gray-100 text-gray-500'}`}
                    title="Chế độ danh sách rút gọn"
                  >
                      <i className={`fas ${isCompactMode ? 'fa-list' : 'fa-th-large'}`}></i>
                  </button>
              </div>
          </div>

          <div className="flex flex-wrap items-center justify-between gap-3 pt-2 border-t border-gray-50">
               <div className="flex gap-2 overflow-x-auto no-scrollbar pb-1">
                    {[OrderStatus.PENDING, OrderStatus.PICKED_UP, OrderStatus.IN_TRANSIT, OrderStatus.DELIVERED].map(s => (
                        <button 
                            key={s} 
                            onClick={() => setFilterStatus(prev => prev.includes(s) ? prev.filter(x => x !== s) : [...prev, s])}
                            className={`px-3 py-1.5 rounded-full text-[10px] font-bold uppercase tracking-wider transition-all border ${filterStatus.includes(s) ? 'bg-black text-white border-black' : 'bg-white text-gray-400 border-gray-200'}`}
                        >
                            {s === OrderStatus.PENDING ? 'Chờ xử lý' : s === OrderStatus.PICKED_UP ? 'Đã lấy' : s === OrderStatus.IN_TRANSIT ? 'Đang giao' : 'Đã giao'}
                        </button>
                    ))}
               </div>
               <div className="flex gap-2">
                    <button onClick={() => setShowRoutePlanner(true)} className="bg-blue-50 text-blue-600 px-3 py-1.5 rounded-lg font-bold text-xs hover:bg-blue-100"><i className="fas fa-map-marked-alt mr-1"></i> Lộ trình</button>
                    <button onClick={exportManifest} className="bg-eco-50 text-eco-700 px-3 py-1.5 rounded-lg font-bold text-xs hover:bg-eco-100"><i className="fas fa-file-pdf mr-1"></i> Bảng kê</button>
                    <button onClick={exportInvoices} className="bg-gray-800 text-white px-3 py-1.5 rounded-lg font-bold text-xs hover:bg-black"><i className="fas fa-print mr-1"></i> In Bill</button>
               </div>
          </div>
      </div>

      {/* 2. ORDER LIST */}
      <div className={isCompactMode ? "bg-white rounded-2xl shadow-sm border border-gray-100 overflow-hidden" : "grid grid-cols-1 md:grid-cols-2 xl:grid-cols-3 gap-4"}>
        {filteredOrders.length === 0 ? (
            <div className="col-span-full py-20 text-center text-gray-400">
                <i className="fas fa-box-open text-4xl mb-3 opacity-20"></i>
                <p className="font-bold">Không tìm thấy đơn hàng nào</p>
            </div>
        ) : (
            filteredOrders.map((order, idx) => (
                <OrderCard 
                    key={order.id}
                    order={order}
                    onDelete={handleDeleteClick}
                    onEdit={(o) => setEditingOrder(o)}
                    onUpdate={() => {}}
                    onViewDetail={(o) => setDetailOrder(o)}
                    onShowQR={handleShowQR}
                    onShip={(o) => { setShipmentOrder(o); setShowShipmentModal(true); }}
                    index={idx}
                    isCompactMode={isCompactMode}
                    isSelectionMode={isSelectionMode}
                    isSelected={selectedOrderIds.has(order.id)}
                    onToggleSelect={toggleSelect}
                />
            ))
        )}
      </div>

      {/* 3. BULK ACTION BAR */}
      {isSelectionMode && (
          <div className="fixed bottom-10 left-1/2 -translate-x-1/2 bg-black text-white px-6 py-4 rounded-2xl shadow-2xl flex items-center gap-6 z-50 animate-bounce-in border border-gray-700">
              <div className="flex flex-col">
                  <span className="text-[10px] text-gray-400 font-bold uppercase">Đang chọn</span>
                  <span className="font-black text-eco-400">{selectedOrderIds.size} đơn</span>
              </div>
              <div className="h-8 w-px bg-gray-700 mx-2"></div>
              <div className="flex gap-4">
                  <button onClick={() => setShowBulkBatchModal(true)} className="flex flex-col items-center gap-1 group">
                      <i className="fas fa-folder-open text-blue-400 group-hover:scale-110 transition-transform"></i>
                      <span className="text-[9px] font-bold">Đổi Lô</span>
                  </button>
                  <button onClick={() => setShowBulkDeleteConfirm(true)} className="flex flex-col items-center gap-1 group">
                      <i className="fas fa-trash-alt text-red-400 group-hover:scale-110 transition-transform"></i>
                      <span className="text-[9px] font-bold">Xóa Hết</span>
                  </button>
                  <button onClick={() => { setSelectedOrderIds(new Set()); setIsSelectionMode(false); }} className="flex flex-col items-center gap-1 group">
                      <i className="fas fa-times text-gray-400"></i>
                      <span className="text-[9px] font-bold">Hủy</span>
                  </button>
              </div>
          </div>
      )}

      {/* --- MODALS --- */}

      {/* 1. Xóa đơn */}
      <ConfirmModal 
        isOpen={showDeleteConfirm} 
        title="Xóa đơn hàng?" 
        message="Hệ thống sẽ tự động hoàn trả số lượng hàng vào kho ngay lập tức." 
        onConfirm={confirmDelete} 
        onCancel={() => setShowDeleteConfirm(false)} 
        isDanger={true} 
      />

      {/* 2. Xóa hàng loạt */}
      <ConfirmModal 
        isOpen={showBulkDeleteConfirm} 
        title={`Xóa ${selectedOrderIds.size} đơn?`} 
        message="Hành động này sẽ xóa vĩnh viễn các đơn đã chọn và hoàn kho tự động cho tất cả sản phẩm." 
        onConfirm={executeBulkDelete} 
        onCancel={() => setShowBulkDeleteConfirm(false)} 
        isDanger={true} 
      />

      {/* 3. Đổi lô hàng loạt */}
      {showBulkBatchModal && (
          <div className="fixed inset-0 z-[100] bg-gray-900/60 backdrop-blur-sm flex items-center justify-center p-4">
              <div className="bg-white rounded-2xl p-6 w-full max-w-sm shadow-2xl">
                  <h3 className="font-bold text-lg mb-4">Chuyển sang Lô hàng mới</h3>
                  <input 
                    placeholder="Nhập tên Lô (VD: LO-25-05)" 
                    value={targetBatch} 
                    onChange={e => setTargetBatch(e.target.value.toUpperCase())}
                    className="w-full p-3 bg-gray-50 border rounded-xl mb-4 outline-none focus:ring-2 focus:ring-blue-200 font-bold"
                  />
                  <div className="flex gap-2">
                      <button onClick={() => setShowBulkBatchModal(false)} className="flex-1 py-2 font-bold text-gray-500">Hủy</button>
                      <button onClick={handleBulkMoveBatch} className="flex-1 py-2 bg-blue-600 text-white rounded-xl font-bold">Xác nhận</button>
                  </div>
              </div>
          </div>
      )}

      {/* 4. QR Code Modal */}
      {qrModal?.isOpen && (
          <div className="fixed inset-0 z-[100] bg-gray-900/80 backdrop-blur-md flex items-center justify-center p-4" onClick={() => setQrModal(null)}>
              <div className="bg-white rounded-3xl p-8 w-full max-w-sm text-center shadow-2xl animate-scale-up" onClick={e => e.stopPropagation()}>
                  <h3 className="font-black text-gray-800 text-xl mb-2">QUÉT MÃ THANH TOÁN</h3>
                  <p className="text-gray-400 text-xs mb-6 uppercase tracking-widest font-bold">Đơn hàng #{qrModal.orderId}</p>
                  <div className="bg-gray-50 p-4 rounded-2xl border-2 border-dashed border-gray-200 mb-6">
                      <img src={qrModal.url} alt="VietQR" className="w-full h-auto rounded-lg shadow-sm" />
                  </div>
                  <button onClick={() => setQrModal(null)} className="w-full py-4 bg-black text-white rounded-2xl font-black tracking-widest hover:bg-gray-800 transition-all">ĐÓNG</button>
              </div>
          </div>
      )}

      {/* Other components */}
      <RoutePlannerModal isOpen={showRoutePlanner} onClose={() => setShowRoutePlanner(false)} orders={filteredOrders} onApplySort={() => {}} />

      {shipmentOrder && (
          <ShipmentModal 
            isOpen={showShipmentModal} 
            onClose={() => setShowShipmentModal(false)} 
            order={shipmentOrder} 
            onSuccess={(data) => {
                storageService.updateStatus(shipmentOrder.id, OrderStatus.IN_TRANSIT, undefined, { carrierData: data });
                setShipmentOrder(null);
            }} 
          />
      )}

      {editingOrder && (
          <div className="fixed inset-0 z-[100] bg-gray-900/60 backdrop-blur-sm flex items-center justify-center p-4">
              <div className="bg-white rounded-2xl p-6 w-full max-w-lg max-h-[90vh] overflow-y-auto">
                  <h3 className="font-bold text-xl mb-4 border-b pb-2">Chỉnh sửa đơn #{editingOrder.id}</h3>
                  {/* Reuse parts of OrderForm or simple edit inputs here */}
                  <div className="space-y-4">
                      <input className="w-full p-2 border rounded" value={editingOrder.customerName} onChange={e => setEditingOrder({...editingOrder, customerName: e.target.value})} />
                      <input className="w-full p-2 border rounded" value={editingOrder.customerPhone} onChange={e => setEditingOrder({...editingOrder, customerPhone: e.target.value})} />
                      <textarea className="w-full p-2 border rounded" value={editingOrder.address} onChange={e => setEditingOrder({...editingOrder, address: e.target.value})} />
                  </div>
                  <div className="flex gap-2 mt-6">
                      <button onClick={() => setEditingOrder(null)} className="flex-1 py-2 font-bold text-gray-500">Hủy</button>
                      <button onClick={async () => {
                          await storageService.updateOrderDetails(editingOrder);
                          toast.success("Đã cập nhật!");
                          setEditingOrder(null);
                      }} className="flex-1 py-2 bg-eco-600 text-white rounded-xl font-bold">Lưu thay đổi</button>
                  </div>
              </div>
          </div>
      )}
    </div>
  );
};

export default TrackingDashboard;

import React, { useEffect, useState, useMemo, useRef, useDeferredValue, useCallback } from 'react';
import toast from 'react-hot-toast';
import { Order, OrderStatus, PaymentMethod, OrderItem, Product, Customer, ShopConfig, BankConfig, CarrierData } from '../types';
import { storageService, normalizePhone, normalizeString } from '../services/storageService';
import { pdfService } from '../services/pdfService';
import { OrderCard } from './OrderCard';
import ConfirmModal from './ConfirmModal';
import RoutePlannerModal from './RoutePlannerModal'; 
import ShipmentModal from './ShipmentModal';
import { ProductDetailModal } from './InventoryManager';

type SortOption = 'NEWEST' | 'ROUTE' | 'CUSTOM';

const TrackingDashboard: React.FC = () => {
  // --- DỮ LIỆU ---
  const [orders, setOrders] = useState<Order[]>([]);
  const [products, setProducts] = useState<Product[]>([]); 
  const [customers, setCustomers] = useState<Customer[]>([]);
  const [bankConfig, setBankConfig] = useState<BankConfig | null>(null);

  // --- BỘ LỌC & HIỂN THỊ ---
  const [filterStatus, setFilterStatus] = useState<OrderStatus[]>([]);
  const [filterBatch, setFilterBatch] = useState<string[]>([]);
  const [searchTerm, setSearchTerm] = useState('');
  const deferredSearchTerm = useDeferredValue(searchTerm);
  const [isCompactMode, setIsCompactMode] = useState(false); 
  const [isSortMode, setIsSortMode] = useState(false);

  // --- CHỌN NHIỀU & THAO TÁC HÀNG LOẠT ---
  const [isSelectionMode, setIsSelectionMode] = useState(false);
  const [selectedOrderIds, setSelectedOrderIds] = useState<Set<string>>(new Set());
  const [showBulkDeleteConfirm, setShowBulkDeleteConfirm] = useState(false);
  const [showBulkBatchModal, setShowBulkBatchModal] = useState(false);
  const [targetBatchName, setTargetBatchName] = useState('');

  // --- MODALS ---
  const [editingOrder, setEditingOrder] = useState<Order | null>(null);
  const [detailOrder, setDetailOrder] = useState<Order | null>(null);
  const [showDeleteConfirm, setShowDeleteConfirm] = useState(false);
  const [deleteId, setDeleteId] = useState<string | null>(null);
  const [showRoutePlanner, setShowRoutePlanner] = useState(false);
  const [shipmentOrder, setShipmentOrder] = useState<Order | null>(null);
  const [showShipmentModal, setShowShipmentModal] = useState(false);
  const [qrModal, setQrModal] = useState<{ isOpen: boolean, url: string, orderId: string } | null>(null);

  // --- DRAG & DROP STATE ---
  const dragItem = useRef<number | null>(null);
  const dragOverItem = useRef<number | null>(null);

  useEffect(() => {
    const unsubOrders = storageService.subscribeOrders(setOrders);
    const unsubProducts = storageService.subscribeProducts(setProducts);
    const unsubCustomers = storageService.subscribeCustomers(setCustomers);
    storageService.getBankConfig().then(setBankConfig);

    return () => { 
        if (unsubOrders) unsubOrders(); 
        if (unsubProducts) unsubProducts();
        if (unsubCustomers) unsubCustomers(); 
    };
  }, []);

  // Lấy danh sách tất cả các Lô hàng để hiển thị bộ lọc
  const allBatches = useMemo(() => {
    const batches = new Set<string>();
    orders.forEach(o => { if (o.batchId) batches.add(o.batchId); });
    return Array.from(batches).sort();
  }, [orders]);

  // Logic lọc và sắp xếp
  const filteredOrders = useMemo(() => {
    let result = orders.filter(o => {
      const statusMatch = filterStatus.length === 0 || filterStatus.includes(o.status);
      const batchMatch = filterBatch.length === 0 || (o.batchId && filterBatch.includes(o.batchId));
      if (!statusMatch || !batchMatch) return false;
      if (!deferredSearchTerm) return true;
      const term = normalizeString(deferredSearchTerm);
      return normalizeString(o.customerName).includes(term) || normalizePhone(o.customerPhone).includes(term) || o.id.toLowerCase().includes(term);
    });

    // Nếu không ở chế độ sắp xếp thủ công, mặc định đơn mới nhất lên đầu
    if (!isSortMode) {
        return result.sort((a, b) => b.createdAt - a.createdAt);
    }
    return result;
  }, [orders, filterStatus, filterBatch, deferredSearchTerm, isSortMode]);

  // --- HANDLERS ---

  const handleLongPress = (id: string) => {
    setIsSelectionMode(true);
    const newSet = new Set(selectedOrderIds);
    newSet.add(id);
    setSelectedOrderIds(newSet);
  };

  const toggleSelect = (id: string) => {
    const newSet = new Set(selectedOrderIds);
    if (newSet.has(id)) newSet.delete(id); else newSet.add(id);
    setSelectedOrderIds(newSet);
    if (newSet.size === 0) setIsSelectionMode(false);
  };

  const confirmDelete = async () => {
    if (deleteId) {
      const toastId = toast.loading("Đang xóa đơn...");
      try {
        await storageService.deleteOrder(deleteId);
        toast.success('Đã xóa đơn & Hoàn kho xong!', { id: toastId });
        setShowDeleteConfirm(false);
        setDeleteId(null);
      } catch (e) { toast.error("Lỗi khi xóa đơn"); }
    }
  };

  const executeBulkDelete = async () => {
    const ids = Array.from(selectedOrderIds) as string[];
    const toastId = toast.loading(`Đang xóa ${ids.length} đơn...`);
    try {
        await storageService.deleteOrdersBatch(ids);
        toast.success(`Đã xóa & Hoàn kho tất cả!`, { id: toastId });
        setSelectedOrderIds(new Set());
        setIsSelectionMode(false);
        setShowBulkDeleteConfirm(false);
    } catch (e) { toast.error("Lỗi xóa hàng loạt"); }
  };

  const handleSplitBatch = async (order: Order) => {
      const nextDate = new Date(order.createdAt + 86400000).toISOString().slice(0, 10);
      const newBatchId = `LO-${nextDate}`;
      await storageService.updateOrderDetails({ ...order, batchId: newBatchId });
      toast.success(`Đã hoãn đơn sang lô ${newBatchId}`);
  };

  // --- DRAG & DROP LOGIC ---
  const handleDragStart = (e: React.DragEvent, index: number) => {
    dragItem.current = index;
  };

  const handleDragEnter = (e: React.DragEvent, index: number) => {
    dragOverItem.current = index;
  };

  const handleDragEnd = () => {
    if (dragItem.current !== null && dragOverItem.current !== null && dragItem.current !== dragOverItem.current) {
        const newList = [...filteredOrders];
        const movedItem = newList.splice(dragItem.current, 1)[0];
        newList.splice(dragOverItem.current, 0, movedItem);
        // Lưu index mới (Tính năng index thủ công nếu cần)
        toast.success("Đã đổi thứ tự!");
    }
    dragItem.current = null;
    dragOverItem.current = null;
  };

  // --- PDF & QR ---
  const handleShowQR = (order: Order) => {
    if (!bankConfig?.accountNo) return toast.error("Chưa cài đặt ngân hàng");
    const qrUrl = `https://img.vietqr.io/image/${bankConfig.bankId}-${bankConfig.accountNo}-compact2.png?amount=${order.totalPrice}&addInfo=${encodeURIComponent('DH '+order.id)}&accountName=${encodeURIComponent(bankConfig.accountName)}`;
    setQrModal({ isOpen: true, url: qrUrl, orderId: order.id });
  };

  const exportManifest = () => {
    const batchName = filterBatch.length === 1 ? filterBatch[0] : "Tong_Hop";
    toast.promise(pdfService.generateCompactList(filteredOrders, batchName), {
        loading: 'Đang tạo bảng kê...',
        success: 'Đã tải PDF!',
        error: 'Lỗi tạo PDF'
    });
  };

  return (
    <div className="animate-fade-in pb-32">
      {/* 1. THANH CÔNG CỤ (STICKY) */}
      <div className="bg-white/90 backdrop-blur-md p-4 rounded-2xl shadow-sm border border-gray-100 mb-6 sticky top-16 z-30 space-y-3">
          <div className="flex flex-col md:flex-row gap-3">
              <div className="relative flex-grow">
                  <i className="fas fa-search absolute left-3 top-3 text-gray-400"></i>
                  <input 
                    placeholder="Tìm tên, SĐT, mã đơn..." 
                    value={searchTerm} 
                    onChange={e => setSearchTerm(e.target.value)}
                    className="w-full pl-10 pr-4 py-2.5 bg-gray-50 rounded-xl outline-none focus:ring-2 focus:ring-eco-200 border-transparent focus:border-eco-500 border transition-all font-medium"
                  />
              </div>
              <div className="flex gap-2">
                  <select 
                    value={filterBatch[0] || 'ALL'} 
                    onChange={e => setFilterBatch(e.target.value === 'ALL' ? [] : [e.target.value])}
                    className="bg-gray-50 px-3 py-2 rounded-xl text-sm font-bold outline-none border-none focus:ring-2 focus:ring-eco-200"
                  >
                      <option value="ALL">Tất cả Lô</option>
                      {allBatches.map(b => <option key={b} value={b}>{b}</option>)}
                  </select>
                  <button 
                    onClick={() => setIsCompactMode(!isCompactMode)}
                    className={`w-10 h-10 rounded-xl flex items-center justify-center transition-all ${isCompactMode ? 'bg-eco-600 text-white' : 'bg-gray-100 text-gray-500'}`}
                  >
                      <i className={`fas ${isCompactMode ? 'fa-list' : 'fa-th-large'}`}></i>
                  </button>
                  <button 
                    onClick={() => setIsSortMode(!isSortMode)}
                    className={`w-10 h-10 rounded-xl flex items-center justify-center transition-all ${isSortMode ? 'bg-orange-500 text-white shadow-inner' : 'bg-gray-100 text-gray-500'}`}
                    title="Chế độ sắp xếp lộ trình thủ công"
                  >
                      <i className="fas fa-route"></i>
                  </button>
              </div>
          </div>

          <div className="flex flex-wrap items-center justify-between gap-3 pt-2 border-t border-gray-100">
               <div className="flex gap-2 overflow-x-auto no-scrollbar">
                    {[OrderStatus.PENDING, OrderStatus.PICKED_UP, OrderStatus.IN_TRANSIT, OrderStatus.DELIVERED].map(s => (
                        <button 
                            key={s} 
                            onClick={() => setFilterStatus(prev => prev.includes(s) ? prev.filter(x => x !== s) : [...prev, s])}
                            className={`px-3 py-1.5 rounded-full text-[10px] font-bold uppercase tracking-wider transition-all border ${filterStatus.includes(s) ? 'bg-black text-white border-black shadow-md' : 'bg-white text-gray-400 border-gray-200'}`}
                        >
                            {s === OrderStatus.PENDING ? 'Chờ' : s === OrderStatus.PICKED_UP ? 'Đã lấy' : s === OrderStatus.IN_TRANSIT ? 'Đang giao' : 'Xong'}
                        </button>
                    ))}
               </div>
               <div className="flex gap-2">
                    <button onClick={() => setShowRoutePlanner(true)} className="bg-blue-50 text-blue-600 px-3 py-1.5 rounded-lg font-bold text-xs hover:bg-blue-100 transition-colors"><i className="fas fa-map-marked-alt mr-1"></i> Lộ trình AI</button>
                    <button onClick={exportManifest} className="bg-eco-50 text-eco-700 px-3 py-1.5 rounded-lg font-bold text-xs hover:bg-eco-100 transition-colors"><i className="fas fa-file-pdf mr-1"></i> Bảng kê</button>
               </div>
          </div>
      </div>

      {/* 2. DANH SÁCH ĐƠN HÀNG */}
      <div className={isCompactMode ? "bg-white rounded-2xl shadow-sm border border-gray-100 overflow-hidden" : "grid grid-cols-1 md:grid-cols-2 xl:grid-cols-3 gap-4"}>
        {filteredOrders.length === 0 ? (
            <div className="col-span-full py-20 text-center text-gray-400 bg-white rounded-3xl border border-dashed border-gray-200">
                <i className="fas fa-search text-5xl mb-4 opacity-10"></i>
                <p className="font-bold">Không tìm thấy đơn hàng nào</p>
                <button onClick={() => {setSearchTerm(''); setFilterStatus([]); setFilterBatch([]);}} className="mt-3 text-eco-600 text-xs font-bold underline">Xóa bộ lọc</button>
            </div>
        ) : (
            filteredOrders.map((order, idx) => (
                <OrderCard 
                    key={order.id}
                    order={order}
                    index={idx}
                    onDelete={(id) => { setDeleteId(id); setShowDeleteConfirm(true); }}
                    onEdit={(o) => setEditingOrder(o)}
                    onUpdate={() => {}}
                    onViewDetail={(o) => setDetailOrder(o)}
                    onShowQR={handleShowQR}
                    onShip={(o) => { setShipmentOrder(o); setShowShipmentModal(true); }}
                    onSplitBatch={handleSplitBatch}
                    onLongPress={handleLongPress}
                    onToggleSelect={toggleSelect}
                    isSelected={selectedOrderIds.has(order.id)}
                    isSelectionMode={isSelectionMode}
                    isCompactMode={isCompactMode}
                    isSortMode={isSortMode}
                    onRowDragStart={handleDragStart}
                    onRowDragEnter={handleDragEnter}
                    onDragEnd={handleDragEnd}
                    onDragOver={(e) => e.preventDefault()}
                    customerData={customers.find(c => c.id === order.customerId || c.phone === order.customerPhone)}
                />
            ))
        )}
      </div>

      {/* 3. THANH THAO TÁC NHANH (KHI CHỌN NHIỀU) */}
      {isSelectionMode && (
          <div className="fixed bottom-10 left-1/2 -translate-x-1/2 bg-gray-900 text-white px-6 py-4 rounded-2xl shadow-2xl flex items-center gap-8 z-[60] animate-bounce-in border border-gray-700">
              <div className="flex flex-col">
                  <span className="text-[10px] text-gray-400 font-bold uppercase">Đã chọn</span>
                  <span className="font-black text-eco-400">{selectedOrderIds.size} đơn</span>
              </div>
              <div className="flex gap-6">
                  <button onClick={() => setShowBulkBatchModal(true)} className="flex flex-col items-center gap-1 group">
                      <i className="fas fa-folder-plus text-blue-400 group-hover:scale-110 transition-transform"></i>
                      <span className="text-[9px] font-bold">Đổi Lô</span>
                  </button>
                  <button onClick={() => setShowBulkDeleteConfirm(true)} className="flex flex-col items-center gap-1 group">
                      <i className="fas fa-trash-alt text-red-400 group-hover:scale-110 transition-transform"></i>
                      <span className="text-[9px] font-bold">Xóa Hết</span>
                  </button>
                  <button onClick={() => { setSelectedOrderIds(new Set()); setIsSelectionMode(false); }} className="flex flex-col items-center gap-1 group">
                      <i className="fas fa-times text-gray-400"></i>
                      <span className="text-[9px] font-bold">Hủy</span>
                  </button>
              </div>
          </div>
      )}

      {/* --- CÁC MODAL HỖ TRỢ --- */}

      {/* 1. Xóa đơn đơn lẻ */}
      <ConfirmModal 
        isOpen={showDeleteConfirm} 
        title="Xóa đơn hàng?" 
        message="Dữ liệu đơn sẽ mất vĩnh viễn và số lượng hàng sẽ được tự động hoàn trả vào kho." 
        onConfirm={confirmDelete} 
        onCancel={() => setShowDeleteConfirm(false)} 
        isDanger={true} 
      />

      {/* 2. Xóa hàng loạt */}
      <ConfirmModal 
        isOpen={showBulkDeleteConfirm} 
        title={`Xóa ${selectedOrderIds.size} đơn đã chọn?`} 
        message="Hành động này sẽ thực hiện hoàn kho cho toàn bộ đơn hàng bị xóa." 
        onConfirm={executeBulkDelete} 
        onCancel={() => setShowBulkDeleteConfirm(false)} 
        isDanger={true} 
      />

      {/* 3. Modal Đổi Lô Hàng Loạt */}
      {showBulkBatchModal && (
          <div className="fixed inset-0 z-[100] bg-gray-900/80 backdrop-blur-sm flex items-center justify-center p-4">
              <div className="bg-white rounded-3xl p-6 w-full max-w-sm shadow-2xl animate-scale-up">
                  <h3 className="font-black text-gray-800 text-xl mb-4">Chuyển Lô Hàng</h3>
                  <p className="text-gray-500 text-sm mb-4">Nhập tên lô mới cho {selectedOrderIds.size} đơn đã chọn:</p>
                  <input 
                    placeholder="VD: LÔ-MAI-GIAO" 
                    value={targetBatchName} 
                    onChange={e => setTargetBatchName(e.target.value.toUpperCase())}
                    className="w-full p-4 bg-gray-50 border-2 border-gray-100 rounded-2xl mb-6 outline-none focus:border-blue-500 font-bold transition-all"
                  />
                  <div className="flex gap-3">
                      <button onClick={() => setShowBulkBatchModal(false)} className="flex-1 py-3 font-bold text-gray-400">Hủy bỏ</button>
                      <button 
                        onClick={async () => {
                            await storageService.moveOrdersBatch(Array.from(selectedOrderIds) as string[], targetBatchName);
                            toast.success("Đã chuyển lô thành công!");
                            setShowBulkBatchModal(false);
                            setIsSelectionMode(false);
                            setSelectedOrderIds(new Set());
                        }} 
                        className="flex-1 py-3 bg-blue-600 text-white rounded-xl font-bold shadow-lg"
                      >Xác nhận</button>
                  </div>
              </div>
          </div>
      )}

      {/* 4. Modal QR Code */}
      {qrModal?.isOpen && (
          <div className="fixed inset-0 z-[100] bg-gray-900/90 backdrop-blur-md flex items-center justify-center p-4" onClick={() => setQrModal(null)}>
              <div className="bg-white rounded-[2rem] p-8 w-full max-w-sm text-center shadow-2xl animate-scale-up" onClick={e => e.stopPropagation()}>
                  <h3 className="font-black text-gray-800 text-xl mb-6 tracking-tight">THANH TOÁN ĐƠN #{qrModal.orderId}</h3>
                  <div className="bg-gray-50 p-4 rounded-3xl border-2 border-dashed border-gray-200 mb-8 overflow-hidden">
