               <div className="bg-white rounded-3xl w-full max-w-lg shadow-2xl overflow-hidden" onClick={e => e.stopPropagation()}>
                    <div className="p-6 border-b border-gray-100 flex justify-between items-start bg-gray-50/50">
                        <div>
                            <h3 className="font-black text-2xl text-gray-800">Đơn hàng #{detailOrder.id}</h3>
                            <div className="text-sm text-gray-500 font-medium mt-1">Lô: {detailOrder.batchId} • {new Date(detailOrder.createdAt).toLocaleString('vi-VN')}</div>
