                    </div>
                    <div className="p-6 space-y-6">
                        <section>
                            <h4 className="text-[10px] font-bold text-gray-400 uppercase tracking-widest mb-3">Thông tin khách</h4>
                            <div className="flex items-center gap-4 bg-gray-50 p-4 rounded-2xl">
                                <div className="w-12 h-12 rounded-full bg-eco-100 flex items-center justify-center text-eco-700 text-lg font-black">{detailOrder.customerName.charAt(0)}</div>
                                <div>
                                    <div className="font-black text-gray-800 text-lg">{detailOrder.customerName}</div>
                                    <div className="text-gray-500 font-mono text-sm">{detailOrder.customerPhone}</div>
                                </div>
