                        <section>
                            <h4 className="text-[10px] font-bold text-gray-400 uppercase tracking-widest mb-3">Sản phẩm đã đặt</h4>
                            <div className="space-y-2">
                                {detailOrder.items.map((it, i) => (
                                    <div key={i} className="flex justify-between items-center bg-gray-50/50 p-3 rounded-xl border border-gray-100">
                                        <div className="font-bold text-gray-800">{it.name} <span className="text-gray-400 font-medium ml-1">x{it.quantity}</span></div>
                                        <div className="font-bold text-blue-600">{new Intl.NumberFormat('vi-VN').format(it.price * it.quantity)}đ</div>
                                    </div>
                                ))}
                            </div>
                        </section>
                        <div className="flex justify-between items-center pt-4 border-t border-gray-100">
                            <span className="font-bold text-gray-400 uppercase text-xs">Tổng thanh toán</span>
                            <span className="font-black text-3xl text-gray-900">{new Intl.NumberFormat('vi-VN').format(detailOrder.totalPrice)}đ</span>
                        </div>
                    </div>
                    <div className="p-6 bg-gray-50 flex gap-3">
                        <button onClick={() => { setEditingOrder(detailOrder); setDetailOrder(null); }} className="flex-1 py-4 bg-black text-white rounded-2xl font-bold shadow-lg shadow-gray-200">SỬA ĐƠN</button>
                        <button onClick={() => { setDeleteId(detailOrder.id); setShowDeleteConfirm(true); setDetailOrder(null); }} className="px-6 py-4 bg-red-50 text-red-600 rounded-2xl font-bold"><i className="fas fa-trash-alt"></i></button>
                    </div>
               </div>
          </div>
      )}

      {/* 6. Modal Chỉnh sửa đơn (Edit Logic) */}
      {editingOrder && (
          <div className="fixed inset-0 z-[110] bg-gray-900/60 backdrop-blur-sm flex items-center justify-center p-4">
              <div className="bg-white rounded-3xl p-6 w-full max-w-lg shadow-2xl animate-fade-in max-h-[90vh] overflow-y-auto">
                  <div className="flex justify-between items-center mb-6">
                      <h3 className="font-black text-xl text-gray-800 uppercase tracking-tight">Sửa đơn #{editingOrder.id}</h3>
                      <button onClick={() => setEditingOrder(null)} className="text-gray-400 hover:text-gray-600"><i className="fas fa-times text-xl"></i></button>
                  </div>
                  <div className="space-y-4">
                      <div>
                          <label className="text-[10px] font-bold text-gray-400 uppercase mb-1 block ml-2">Tên khách hàng</label>
                          <input className="w-full p-4 bg-gray-50 border-none rounded-2xl font-bold text-gray-800 focus:ring-2 focus:ring-blue-100 outline-none" value={editingOrder.customerName} onChange={e => setEditingOrder({...editingOrder, customerName: e.target.value})} />
                      </div>
                      <div>
                          <label className="text-[10px] font-bold text-gray-400 uppercase mb-1 block ml-2">Số điện thoại</label>
                          <input className="w-full p-4 bg-gray-50 border-none rounded-2xl font-bold text-gray-800 focus:ring-2 focus:ring-blue-100 outline-none" value={editingOrder.customerPhone} onChange={e => setEditingOrder({...editingOrder, customerPhone: e.target.value})} />
                      </div>
                      <div>
                          <label className="text-[10px] font-bold text-gray-400 uppercase mb-1 block ml-2">Địa chỉ nhận hàng</label>
                          <textarea className="w-full p-4 bg-gray-50 border-none rounded-2xl font-medium text-gray-700 focus:ring-2 focus:ring-blue-100 outline-none resize-none" rows={3} value={editingOrder.address} onChange={e => setEditingOrder({...editingOrder, address: e.target.value})} />
                      </div>
                      <div>
                          <label className="text-[10px] font-bold text-gray-400 uppercase mb-1 block ml-2">Ghi chú vận chuyển</label>
                          <input className="w-full p-4 bg-gray-50 border-none rounded-2xl font-medium text-orange-600 focus:ring-2 focus:ring-orange-100 outline-none" value={editingOrder.notes} onChange={e => setEditingOrder({...editingOrder, notes: e.target.value})} />
                      </div>
                  </div>
                  <div className="flex gap-4 mt-8">
                      <button onClick={() => setEditingOrder(null)} className="flex-1 py-4 font-bold text-gray-400">Hủy bỏ</button>
                      <button 
                        onClick={async () => {
                            await storageService.updateOrderDetails(editingOrder);
                            toast.success("Đã cập nhật chi tiết đơn!");
                            setEditingOrder(null);
                        }} 
                        className="flex-1 py-4 bg-eco-600 text-white rounded-2xl font-black shadow-lg shadow-eco-100 active:scale-95 transition-all"
                      >LƯU THAY ĐỔI</button>
                  </div>
              </div>
          </div>
      )}

      {/* 7. Route Planner & Shipment Modals */}
      <RoutePlannerModal isOpen={showRoutePlanner} onClose={() => setShowRoutePlanner(false)} orders={filteredOrders} onApplySort={() => {}} />

      {shipmentOrder && (
          <ShipmentModal 
            isOpen={showShipmentModal} 
            onClose={() => setShowShipmentModal(false)} 
            order={shipmentOrder} 
            onSuccess={(data) => {
                storageService.updateStatus(shipmentOrder.id, OrderStatus.IN_TRANSIT, undefined, { carrierData: data });
                setShipmentOrder(null);
            }} 
          />
      )}
    </div>
  );
};

export default TrackingDashboard;

