import { Order, OrderStatus, Product, Customer, BankConfig, Notification, ShopConfig, ImportRecord, PaymentMethod } from '../types';
import { db } from '../firebaseConfig';
import { v4 as uuidv4 } from 'uuid';
import { 
  collection, 
  setDoc, 
  doc, 
  updateDoc, 
  deleteDoc, 
  onSnapshot, 
  query, 
  orderBy, 
  getDocs, 
  writeBatch, 
  deleteField, 
  limit, 
  getDoc, 
  where, 
  increment,
  runTransaction 
} from "firebase/firestore";

const ORDER_KEY = 'ecogo_orders_v3'; 
const PRODUCT_KEY = 'ecogo_products_v1';
const CUSTOMER_KEY = 'ecogo_customers_v1';
const USER_KEY = 'ecogo_current_user';
const BANK_KEY = 'ecogo_bank_config';
const SHOP_KEY = 'ecogo_shop_config';
const NOTIF_KEY = 'ecogo_notifications_v1';
const TAGS_KEY = 'ecogo_quick_tags';
const QUOTA_KEY = 'ecogo_quota_status';
const LOGO_KEY = 'ecogo_company_logo';

// --- QUOTA & ONLINE CHECK ---
const checkQuotaStatus = () => {
    try {
        const stored = localStorage.getItem(QUOTA_KEY);
        if (stored) {
            const { date, exhausted } = JSON.parse(stored);
            const today = new Date().toDateString();
            if (date === today && exhausted) return true;
        }
    } catch {}
    return false;
};

let _quotaExhausted = checkQuotaStatus();
const markQuotaExhausted = () => {
    if (!_quotaExhausted) {
        _quotaExhausted = true;
        localStorage.setItem(QUOTA_KEY, JSON.stringify({ date: new Date().toDateString(), exhausted: true }));
        window.dispatchEvent(new Event('quota_exhausted'));
    }
};

const isOnline = () => !!db && !_quotaExhausted;
const isQuotaError = (e: any): boolean => {
    const msg = (e?.message || '').toLowerCase();
    return e?.code === 'resource-exhausted' || msg.includes('quota');
};

// --- IN-MEMORY CACHE ---
let _memoryCustomers: Customer[] | null = null;
let _memoryOrders: Order[] | null = null;
let _memoryProducts: Product[] | null = null;

const ensureCustomersLoaded = () => {
    if (_memoryCustomers) return _memoryCustomers;
    const local = localStorage.getItem(CUSTOMER_KEY);
    _memoryCustomers = local ? JSON.parse(local) : [];
    return _memoryCustomers!;
};

const ensureOrdersLoaded = () => {
    if (_memoryOrders) return _memoryOrders;
    const local = localStorage.getItem(ORDER_KEY);
    _memoryOrders = local ? JSON.parse(local) : [];
    return _memoryOrders!;
};

const ensureProductsLoaded = () => {
    if (_memoryProducts) return _memoryProducts;
    const local = localStorage.getItem(PRODUCT_KEY);
    _memoryProducts = local ? JSON.parse(local) : [];
    return _memoryProducts!;
};

const safeCloudOp = async (operation: () => Promise<any>) => {
    if (!isOnline()) return;
    try { await operation(); } catch (error: any) {
        if (isQuotaError(error)) markQuotaExhausted();
        else console.warn("Cloud Sync Error:", error.message);
    }
};

const sanitize = <T>(obj: T): T => JSON.parse(JSON.stringify(obj));

export const normalizeString = (str: string): string => {
    if (!str) return "";
    return str.normalize("NFD").replace(/[\u0300-\u036f]/g, "").replace(/đ/g, "d").replace(/Đ/g, "D").replace(/[^a-zA-Z0-9]/g, "").toLowerCase();
};

export const normalizePhone = (phone: string) => {
    if (!phone) return '';
    let p = phone.replace(/[^0-9]/g, '');
    if (p.startsWith('84')) p = '0' + p.slice(2);
    if (p.startsWith('+84')) p = '0' + p.slice(3);
    if (p.length === 9 && !p.startsWith('0')) p = '0' + p;
    return p;
};

export const generateProductSku = (name: string): string => {
    if (!name) return uuidv4();
    const sku = name.normalize("NFD").replace(/[\u0300-\u036f]/g, "").replace(/đ/g, "d").replace(/Đ/g, "D").trim().toUpperCase().replace(/[^A-Z0-9]+/g, "_");
    return sku.length < 2 ? uuidv4() : sku;
};

export const storageService = {
  login: (username: string) => { localStorage.setItem(USER_KEY, username); },
  logout: () => { localStorage.removeItem(USER_KEY); },
  getCurrentUser: (): string | null => localStorage.getItem(USER_KEY),

  // --- LOGO & TAGS ---
  getLogo: () => localStorage.getItem(LOGO_KEY),
  saveLogo: (base64: string) => { localStorage.setItem(LOGO_KEY, base64); window.dispatchEvent(new Event('logo_updated')); },
  removeLogo: () => { localStorage.removeItem(LOGO_KEY); window.dispatchEvent(new Event('logo_updated')); },
  getQuickTags: () => { try { return JSON.parse(localStorage.getItem(TAGS_KEY) || '[]'); } catch { return ["Dễ vỡ", "Giao gấp"]; } },
  saveQuickTags: async (tags: string[]) => { localStorage.setItem(TAGS_KEY, JSON.stringify(tags)); await safeCloudOp(() => setDoc(doc(db, "settings", "quickTags"), { tags })); },
  fetchQuickTagsFromCloud: async () => {
      if (isOnline()) {
          const snap = await getDoc(doc(db, "settings", "quickTags"));
          if (snap.exists()) {
              const tags = (snap.data() as any).tags;
              localStorage.setItem(TAGS_KEY, JSON.stringify(tags));
              return tags;
          }
      }
      return storageService.getQuickTags();
  },

  // --- CONFIG ---
  getShopConfig: async () => JSON.parse(localStorage.getItem(SHOP_KEY) || '{"shopName":"EcoGo","hotline":""}'),
  saveShopConfig: async (config: ShopConfig) => { localStorage.setItem(SHOP_KEY, JSON.stringify(config)); await safeCloudOp(() => setDoc(doc(db, "settings", "shopConfig"), sanitize(config))); },
  getBankConfig: async () => JSON.parse(localStorage.getItem(BANK_KEY) || 'null'),
  saveBankConfig: async (config: BankConfig) => { localStorage.setItem(BANK_KEY, JSON.stringify(config)); await safeCloudOp(() => setDoc(doc(db, "settings", "bankConfig"), sanitize(config))); },

  // --- PRODUCTS ---
  subscribeProducts: (callback: (products: Product[]) => void) => {
    const list = ensureProductsLoaded();
    callback(list);
    if (isOnline()) {
        return onSnapshot(collection(db, "products"), (snap) => {
            const cloudProds: Product[] = [];
            snap.forEach(d => cloudProds.push(d.data() as Product));
            if (cloudProds.length > 0) {
                _memoryProducts = cloudProds;
                localStorage.setItem(PRODUCT_KEY, JSON.stringify(cloudProds));
                callback(cloudProds);
            }
        });
    }
  },

  saveProduct: async (product: Product) => {
      const pSave = { ...product, updatedAt: Date.now() };
      const list = ensureProductsLoaded();
      const idx = list.findIndex(p => p.id === pSave.id);
      if (idx >= 0) list[idx] = pSave; else list.push(pSave);
      localStorage.setItem(PRODUCT_KEY, JSON.stringify(list));
      window.dispatchEvent(new Event('storage_' + PRODUCT_KEY));
      await safeCloudOp(() => setDoc(doc(db, "products", pSave.id), sanitize(pSave)));
  },

  deleteProduct: async (id: string) => {
      const prods = ensureProductsLoaded();
      const newList = prods.filter(p => p.id !== id);
      _memoryProducts = newList;
      localStorage.setItem(PRODUCT_KEY, JSON.stringify(newList));
      await safeCloudOp(() => deleteDoc(doc(db, "products", id)));
  },

  getProductBySku: (sku: string) => {
      const prods = ensureProductsLoaded();
      return prods.find(p => p.id === sku);
  },

  getAllProducts: () => ensureProductsLoaded(),

  syncProductToPendingOrders: async (product: Product) => {
      const orders = ensureOrdersLoaded();
      let count = 0;
      orders.forEach(o => {
          if (o.status === OrderStatus.PENDING || o.status === OrderStatus.PICKED_UP) {
              let changed = false;
              o.items.forEach(it => {
                  if (it.productId === product.id) {
                      it.name = product.name;
                      it.price = product.defaultPrice;
                      it.importPrice = product.importPrice;
                      changed = true;
                  }
              });
              if (changed) count++;
          }
      });
      if (count > 0) {
          localStorage.setItem(ORDER_KEY, JSON.stringify(orders));
          await safeCloudOp(async () => {
              const batch = writeBatch(db);
              orders.forEach(o => {
                  if (o.status === OrderStatus.PENDING || o.status === OrderStatus.PICKED_UP) {
                      batch.update(doc(db, "orders", o.id), { items: o.items, updatedAt: Date.now() });
                  }
              });
              await batch.commit();
          });
      }
      return count;
  },

  cleanAndMergeDuplicateProducts: async () => {
      const prods = ensureProductsLoaded();
      const nameMap = new Map<string, Product[]>();
      prods.forEach(p => {
          const norm = normalizeString(p.name);
          if (!nameMap.has(norm)) nameMap.set(norm, []);
          nameMap.get(norm)!.push(p);
      });

      let mergedCount = 0;
      let fixedOrders = 0;

      for (const group of nameMap.values()) {
          if (group.length > 1) {
              const master = group[0];
              const duplicates = group.slice(1);

              duplicates.forEach(dup => {
                  master.stockQuantity += dup.stockQuantity;
                  master.totalImported = (master.totalImported || 0) + (dup.totalImported || 0);
                  const orders = ensureOrdersLoaded();
                  orders.forEach(o => {
                      o.items.forEach(it => {
                          if (it.productId === dup.id) {
                              it.productId = master.id;
                              fixedOrders++;
                          }
                      });
                  });
              });

              for(const dup of duplicates) {
                  await storageService.deleteProduct(dup.id);
              }
              await storageService.saveProduct(master);
              mergedCount += duplicates.length;
          }
      }
      return { mergedCount, fixedOrders };
  },

  getProductOrderHistory: (productId: string) => {
      const orders = ensureOrdersLoaded();
      const history: {order: Order, quantity: number}[] = [];
      orders.forEach(o => {
          const item = o.items.find(it => it.productId === productId);
          if (item) history.push({ order: o, quantity: item.quantity });
      });
      return history;
  },

  adjustStockAtomic: async (productId: string, delta: number, importInfo?: any) => {
      const products = ensureProductsLoaded();
      const p = products.find(x => x.id === productId);
      if (p) {
          p.stockQuantity = (p.stockQuantity || 0) + delta;
          if (delta > 0) p.totalImported = (p.totalImported || 0) + delta;
          localStorage.setItem(PRODUCT_KEY, JSON.stringify(products));
      }
      await safeCloudOp(async () => {
          await runTransaction(db, async (tx) => {
              const ref = doc(db, "products", productId);
              const snap = await tx.get(ref);
              if (snap.exists()) {
                  const updates: any = { stockQuantity: increment(delta), updatedAt: Date.now() };
                  if (delta > 0) updates.totalImported = increment(delta);
                  tx.update(ref, updates);
              }
          });
      });
  },

  // --- CUSTOMERS ---
  subscribeCustomers: (callback: (customers: Customer[]) => void) => {
      const list = ensureCustomersLoaded();
      callback(list);
      if (isOnline()) {
          return onSnapshot(collection(db, "customers"), (snap) => {
              const items: Customer[] = [];
              snap.forEach(d => items.push(d.data() as Customer));
              if (items.length > 0) {
                  _memoryCustomers = items;
                  localStorage.setItem(CUSTOMER_KEY, JSON.stringify(items));
                  callback(items);
              }
          });
      }
  },

  upsertCustomer: async (customer: Customer) => {
      const list = ensureCustomersLoaded();
      const idx = list.findIndex(c => c.id === customer.id);
      const cSave = { ...customer, updatedAt: Date.now() };
      if (idx >= 0) list[idx] = cSave; else list.push(cSave);
      localStorage.setItem(CUSTOMER_KEY, JSON.stringify(list));
      await safeCloudOp(() => setDoc(doc(db, "customers", cSave.id), sanitize(cSave)));
  },

  importCustomersBatch: async (customers: Customer[], isLocal: boolean) => {
      const list = ensureCustomersLoaded();
      customers.forEach(c => {
          const idx = list.findIndex(existing => existing.id === c.id);
          if (idx >= 0) list[idx] = c; else list.push(c);
      });
      localStorage.setItem(CUSTOMER_KEY, JSON.stringify(list));
      if (!isLocal && isOnline()) {
          const batchSize = 100;
          for (let i = 0; i < customers.length; i += batchSize) {
              const batch = writeBatch(db);
              const chunk = customers.slice(i, i + batchSize);
              chunk.forEach(c => batch.set(doc(db, "customers", c.id), sanitize(c)));
              await batch.commit();
          }
      }
  },

  deleteCustomer: async (id: string) => {
      const list = ensureCustomersLoaded();
      const newList = list.filter(c => c.id !== id);
      _memoryCustomers = newList;
      localStorage.setItem(CUSTOMER_KEY, JSON.stringify(newList));
      await safeCloudOp(() => deleteDoc(doc(db, "customers", id)));
  },

  clearAllCustomers: async (isLocal: boolean) => {
      localStorage.setItem(CUSTOMER_KEY, JSON.stringify([]));
      _memoryCustomers = [];
      if (!isLocal && isOnline()) {
          const snap = await getDocs(collection(db, "customers"));
          const batch = writeBatch(db);
          snap.forEach(d => batch.delete(d.ref));
          await batch.commit();
      }
  },

  findMatchingCustomer: (phone: string, address: string, id?: string) => {
      const list = ensureCustomersLoaded();
      if (id) {
          const found = list.find(c => c.id === id);
          if (found) return found;
      }
      if (phone && phone.length > 5) {
          const found = list.find(c => c.phone === phone);
          if (found) return found;
      }
      return list.find(c => normalizeString(c.address) === normalizeString(address));
  },

  isNewCustomer: (phone: string, address: string, id?: string) => {
      const orders = ensureOrdersLoaded();
      if (id) return !orders.some(o => o.customerId === id);
      const cleanPhone = normalizePhone(phone);
      if (cleanPhone && cleanPhone.length > 5) return !orders.some(o => normalizePhone(o.customerPhone) === cleanPhone);
      return !orders.some(o => normalizeString(o.address) === normalizeString(address));
  },

  // --- ORDERS CORE (REFACTORED FOR ATOMICITY) ---
  subscribeOrders: (callback: (orders: Order[]) => void) => {
    const list = ensureOrdersLoaded();
    callback(list);
    if (isOnline()) {
        const q = query(collection(db, "orders"), orderBy("createdAt", "desc"), limit(600));
        return onSnapshot(q, (snap) => {
            const fetched: Order[] = [];
            snap.forEach(d => fetched.push(d.data() as Order));
            _memoryOrders = fetched;
            localStorage.setItem(ORDER_KEY, JSON.stringify(fetched));
            callback(fetched);
        });
    }
  },

  saveOrder: async (order: Order) => {
    const now = Date.now();
    const orderWithMeta = { ...order, lastUpdatedBy: storageService.getCurrentUser() || 'System', updatedAt: now };

    // 1. Local Update (Optimistic)
    const list = ensureOrdersLoaded();
    list.unshift(orderWithMeta);
    localStorage.setItem(ORDER_KEY, JSON.stringify(list));

    const prods = ensureProductsLoaded();
    order.items.forEach(it => {
        if (it.productId) {
            const p = prods.find(x => x.id === it.productId);
            if (p) p.stockQuantity = (p.stockQuantity || 0) - it.quantity;
        }
    });
    localStorage.setItem(PRODUCT_KEY, JSON.stringify(prods));

    // 2. Cloud Atomic Transaction
    await safeCloudOp(async () => {
        await runTransaction(db, async (tx) => {
            for (const it of order.items) {
                if (it.productId) {
                    const pRef = doc(db, "products", it.productId);
                    tx.update(pRef, { stockQuantity: increment(-it.quantity), updatedAt: now });
                }
            }
            tx.set(doc(db, "orders", order.id), sanitize(orderWithMeta));
        });
    });
  },

  deleteOrder: async (id: string, meta?: any) => {
      const orders = ensureOrdersLoaded();
      const order = orders.find(o => o.id === id);
      if (!order) return;

      const now = Date.now();

      // 1. Local Optimistic Update
      const newOrders = orders.filter(o => o.id !== id);
      _memoryOrders = newOrders;
      localStorage.setItem(ORDER_KEY, JSON.stringify(newOrders));

      if (order.status !== OrderStatus.CANCELLED) {
          const prods = ensureProductsLoaded();
          order.items.forEach(it => {
              if (it.productId) {
                  const p = prods.find(x => x.id === it.productId);
                  if (p) p.stockQuantity = (p.stockQuantity || 0) + it.quantity;
              }
          });
          localStorage.setItem(PRODUCT_KEY, JSON.stringify(prods));
      }

      // 2. Cloud Atomic Delete + Stock Restore
      await safeCloudOp(async () => {
          await runTransaction(db, async (tx) => {
              const orderRef = doc(db, "orders", id);
              if (order.status !== OrderStatus.CANCELLED) {
                  for (const it of order.items) {
                      if (it.productId) {
                          const pRef = doc(db, "products", it.productId);
                          tx.update(pRef, { stockQuantity: increment(it.quantity), updatedAt: now });
                      }
                  }
              }
              tx.delete(orderRef);
          });
      });
  },

  updateStatus: async (id: string, status: OrderStatus, deliveryProof?: string, meta?: any) => {
    const orders = ensureOrdersLoaded();
    const idx = orders.findIndex(o => o.id === id);
    if (idx === -1) return;

    const oldOrder = orders[idx];
    const now = Date.now();

    let stockDelta = 0;
    if (status === OrderStatus.CANCELLED && oldOrder.status !== OrderStatus.CANCELLED) {
        stockDelta = 1; 
    } else if (oldOrder.status === OrderStatus.CANCELLED && status !== OrderStatus.CANCELLED) {
        stockDelta = -1; 
    }

    const updated = { 
        ...oldOrder, 
        status, 
        deliveryProof: deliveryProof !== undefined ? deliveryProof : oldOrder.deliveryProof,
        updatedAt: now, 
        lastUpdatedBy: storageService.getCurrentUser() || 'System' 
    };
    orders[idx] = updated;
    localStorage.setItem(ORDER_KEY, JSON.stringify(orders));

    if (stockDelta !== 0) {
        const prods = ensureProductsLoaded();
        oldOrder.items.forEach(it => {
            if (it.productId) {
                const p = prods.find(x => x.id === it.productId);
                if (p) p.stockQuantity = (p.stockQuantity || 0) + (it.quantity * stockDelta);
            }
        });
        localStorage.setItem(PRODUCT_KEY, JSON.stringify(prods));
    }

    await safeCloudOp(async () => {
        await runTransaction(db, async (tx) => {
            if (stockDelta !== 0) {
                for (const it of oldOrder.items) {
                    if (it.productId) {
                        tx.update(doc(db, "products", it.productId), { 
                            stockQuantity: increment(it.quantity * stockDelta), 
                            updatedAt: now 
                        });
                    }
                }
            }
            const updates: any = { status, updatedAt: now, lastUpdatedBy: updated.lastUpdatedBy };
            if (deliveryProof !== undefined) updates.deliveryProof = deliveryProof;
            tx.update(doc(db, "orders", id), updates);
        });
    });
  },

  deleteDeliveryProof: async (id: string) => {
      const orders = ensureOrdersLoaded();
      const idx = orders.findIndex(o => o.id === id);
      if (idx !== -1) {
          orders[idx].deliveryProof = undefined;
          localStorage.setItem(ORDER_KEY, JSON.stringify(orders));
      }
      await safeCloudOp(() => updateDoc(doc(db, "orders", id), { deliveryProof: deleteField(), updatedAt: Date.now() }));
  },

  updateOrderDetails: async (order: Order) => {
    const now = Date.now();
    const orders = ensureOrdersLoaded();
    const idx = orders.findIndex(o => o.id === order.id);
    if (idx === -1) return;

    const oldOrder = orders[idx];
    const productDeltas = new Map<string, number>();

    if (oldOrder.status !== OrderStatus.CANCELLED) {
        oldOrder.items.forEach(it => { if(it.productId) productDeltas.set(it.productId, (productDeltas.get(it.productId) || 0) + it.quantity); });
    }
    if (order.status !== OrderStatus.CANCELLED) {
        order.items.forEach(it => { if(it.productId) productDeltas.set(it.productId, (productDeltas.get(it.productId) || 0) - it.quantity); });
    }

    orders[idx] = { ...order, updatedAt: now };
    localStorage.setItem(ORDER_KEY, JSON.stringify(orders));

    const prods = ensureProductsLoaded();
    productDeltas.forEach((delta, pid) => {
        const p = prods.find(x => x.id === pid);
        if (p) p.stockQuantity = (p.stockQuantity || 0) + delta;
    });
    localStorage.setItem(PRODUCT_KEY, JSON.stringify(prods));

    await safeCloudOp(async () => {
        await runTransaction(db, async (tx) => {
            for (const [pid, delta] of productDeltas.entries()) {
                if (Math.abs(delta) > 0) {
                    tx.update(doc(db, "products", pid), { stockQuantity: increment(delta), updatedAt: now });
                }
            }
            tx.set(doc(db, "orders", order.id), sanitize({ ...order, updatedAt: now }));
        });
    });
  },

  updatePaymentVerification: async (id: string, verified: boolean, meta?: any) => {
      await safeCloudOp(() => updateDoc(doc(db, "orders", id), { paymentVerified: verified, updatedAt: Date.now() }));
  },

  incrementReminderCount: async (ids: string[]) => {
      await safeCloudOp(async () => {
          const batch = writeBatch(db);
          ids.forEach(id => batch.update(doc(db, "orders", id), { reminderCount: increment(1), updatedAt: Date.now() }));
          await batch.commit();
      });
  },

  deleteOrdersBatch: async (ids: string[]) => {
      for (const id of ids) { await storageService.deleteOrder(id); }
  },

  moveOrdersBatch: async (ids: string[], targetBatch: string) => {
      await safeCloudOp(async () => {
          const batch = writeBatch(db);
          ids.forEach(id => batch.update(doc(db, "orders", id), { batchId: targetBatch, updatedAt: Date.now() }));
          await batch.commit();
      });
  },

  splitOrderToNextBatch: async (id: string, currentBatch: string) => {
      const now = new Date();
      now.setDate(now.getDate() + 1);
      const nextBatch = `LÔ-${now.toISOString().slice(0, 10)}`;
      await safeCloudOp(() => updateDoc(doc(db, "orders", id), { batchId: nextBatch, updatedAt: Date.now() }));
  },

  splitOrdersBatch: async (subset: { id: string, batchId: string }[]) => {
      const now = new Date();
      now.setDate(now.getDate() + 1);
      const nextBatch = `LÔ-${now.toISOString().slice(0, 10)}`;
      await safeCloudOp(async () => {
          const batch = writeBatch(db);
          subset.forEach(item => batch.update(doc(db, "orders", item.id), { batchId: nextBatch, updatedAt: Date.now() }));
          await batch.commit();
      });
  },

  renameBatch: async (oldName: string, newName: string) => {
      const orders = ensureOrdersLoaded();
      const batch = writeBatch(db);
      let count = 0;
      orders.forEach(o => {
          if (o.batchId === oldName) {
              batch.update(doc(db, "orders", o.id), { batchId: newName, updatedAt: Date.now() });
              count++;
          }
      });
      if (count > 0) await safeCloudOp(() => batch.commit());
  },

  saveOrdersList: async (reorderedList: Order[]) => {
      const batch = writeBatch(db);
      reorderedList.forEach(o => {
          batch.update(doc(db, "orders", o.id), { orderIndex: o.orderIndex, updatedAt: Date.now() });
      });
      await safeCloudOp(() => batch.commit());
  },

  learnRoutePriority: async (list: Order[]) => {
      await safeCloudOp(async () => {
          const batch = writeBatch(db);
          for (let i = 0; i < list.length; i++) {
              const o = list[i];
              const customer = storageService.findMatchingCustomer(o.customerPhone, o.address, o.customerId);
              if (customer) {
                  batch.update(doc(db, "customers", customer.id), { priorityScore: i + 1, updatedAt: Date.now() });
              }
          }
          await batch.commit();
      });
  },

  // --- TOOLS ---
  recalculateInventoryFromOrders: async () => {
      const prods = ensureProductsLoaded();
      const orders = ensureOrdersLoaded();
      const soldMap = new Map<string, number>();

      orders.filter(o => o.status !== OrderStatus.CANCELLED).forEach(o => {
          o.items.forEach(it => {
              if (it.productId) soldMap.set(it.productId, (soldMap.get(it.productId) || 0) + it.quantity);
          });
      });

      prods.forEach(p => {
          const totalSold = soldMap.get(p.id) || 0;
          const totalImported = p.totalImported || (p.stockQuantity + totalSold);
          p.stockQuantity = Math.max(0, totalImported - totalSold);
          p.totalImported = totalImported;
      });

      localStorage.setItem(PRODUCT_KEY, JSON.stringify(prods));
      for (const p of prods) { await storageService.saveProduct(p); }
      return prods.length;
  },

  fetchLongTermStats: async () => {
      if (isOnline()) {
          const snap = await getDocs(collection(db, "orders"));
          const items: Order[] = [];
          snap.forEach(d => items.push(d.data() as Order));
          return items;
      }
      return ensureOrdersLoaded();
  },

  syncLocalToCloud: async () => {
      const orders = ensureOrdersLoaded();
      const products = ensureProductsLoaded();
      const customers = ensureCustomersLoaded();

      await safeCloudOp(async () => {
          const batch = writeBatch(db);
          orders.forEach(o => batch.set(doc(db, "orders", o.id), sanitize(o)));
          products.forEach(p => batch.set(doc(db, "products", p.id), sanitize(p)));
          customers.forEach(c => batch.set(doc(db, "customers", c.id), sanitize(c)));
          await batch.commit();
      });
      return orders.length;
  },

  generatePerformanceData: async (count: number) => {
      const start = Date.now();
      const newCustomers: Customer[] = [];
      for (let i = 0; i < count; i++) {
          newCustomers.push({
              id: uuidv4(),
              name: `Stress Test ${i}`,
              phone: `09${Math.floor(Math.random() * 90000000 + 10000000)}`,
              address: `${i} Mock Street, Test City`,
              lastOrderDate: Date.now(),
              priorityScore: 999
          });
      }
      await storageService.importCustomersBatch(newCustomers, true);
      return { count, duration: Date.now() - start };
  },

  markAllCustomersAsOld: async () => {
      const list = ensureCustomersLoaded();
      list.forEach(c => c.isLegacy = true);
      localStorage.setItem(CUSTOMER_KEY, JSON.stringify(list));
      await storageService.importCustomersBatch(list, false);
      return list.length;
  },

  fixDuplicateCustomerIds: async () => {
      const list = ensureCustomersLoaded();
      const idMap = new Map<string, number>();
      let fixed = 0;
      list.forEach(c => {
          if (idMap.has(c.id)) {
              c.id = uuidv4();
              fixed++;
          }
          idMap.set(c.id, 1);
      });
      if (fixed > 0) {
          localStorage.setItem(CUSTOMER_KEY, JSON.stringify(list));
          await storageService.importCustomersBatch(list, false);
      }
      return fixed;
  },

  mergeCustomersByPhone: async () => {
      const list = ensureCustomersLoaded();
      const phoneMap = new Map<string, Customer[]>();
      list.forEach(c => {
          if (c.phone && c.phone.length > 5) {
              if (!phoneMap.has(c.phone)) phoneMap.set(c.phone, []);
              phoneMap.get(c.phone)!.push(c);
          }
      });
      let count = 0;
      for (const group of phoneMap.values()) {
          if (group.length > 1) count++;
      }
      return count;
  },

  // --- NOTIFICATIONS ---
  subscribeNotifications: (cb: (n: Notification[]) => void) => {
      if (isOnline()) {
          return onSnapshot(query(collection(db, "notifications"), orderBy('createdAt', 'desc'), limit(40)), (snap) => {
              const list: Notification[] = [];
              snap.forEach(d => list.push(d.data() as Notification));
              cb(list);
          });
      }
  },

  markNotificationRead: async (id: string) => {
      await safeCloudOp(() => updateDoc(doc(db, "notifications", id), { isRead: true }));
  },

  markAllNotificationsRead: async () => {
      await safeCloudOp(async () => {
          const q = query(collection(db, "notifications"), where("isRead", "==", false));
          const snap = await getDocs(q);
          const batch = writeBatch(db);
          snap.forEach(d => batch.update(d.ref, { isRead: true }));
          await batch.commit();
      });
  },

  clearAllNotifications: async () => {
      await safeCloudOp(async () => {
          const snap = await getDocs(collection(db, "notifications"));
          const batch = writeBatch(db);
          snap.forEach(d => batch.delete(d.ref));
          await batch.commit();
      });
  }
};

