  const handleSplitBatch = async (order: Order) => { await storageService.splitOrderToNextBatch(order.id, order.batchId); toast.success('Đã chuyển đơn sang lô sau!'); setDetailOrder(null); };

  const handleShowQR = async (order: Order) => { 
      const bankConfig = await storageService.getBankConfig(); 
      if (!bankConfig?.accountNo) return toast.error("Chưa cài đặt Ngân hàng."); 
      const url = `https://img.vietqr.io/image/${bankConfig.bankId}-${bankConfig.accountNo}-compact2.png?amount=${order.totalPrice}&addInfo=${encodeURIComponent('DH '+order.id)}&accountName=${encodeURIComponent(bankConfig.accountName)}`; 
      setQrState({ isOpen: true, url, order }); 
  };

  const handleShipOrder = (order: Order) => { setShipmentOrder(order); setShowShipmentModal(true); };

  // Fix: Defined handleShipmentSuccess to update the order with carrier data upon successful shipment creation
  const handleShipmentSuccess = async (carrierData: CarrierData) => {
      if (!shipmentOrder) return;
      const updatedOrder = { ...shipmentOrder, carrierData };
      await storageService.updateOrderDetails(updatedOrder);
  };

  const handleShareQR = async () => {
        if (!qrState.url || !qrState.order || !qrImgRef.current) return;
        const toastId = toast.loading("Đang tạo ảnh...");
        try {
            const order = qrState.order;
            const W = 800;
            const qrSize = 500;
            const drawHeight = qrSize; 
            let H = 600 + (order.items.length * 50); 

            const canvas = document.createElement('canvas');
            const ctx = canvas.getContext('2d')!;
            canvas.width = W; canvas.height = H;
            ctx.fillStyle = '#ffffff'; ctx.fillRect(0, 0, W, H);

            ctx.fillStyle = '#15803d'; ctx.fillRect(0, 0, W, 140);
            ctx.fillStyle = '#ffffff'; ctx.font = 'bold 40px Arial'; ctx.textAlign = 'center';
            ctx.fillText('QUÉT MÃ THANH TOÁN', W / 2, 85);

            ctx.fillStyle = '#15803d'; ctx.font = 'bold 60px Arial';
            ctx.fillText(`${new Intl.NumberFormat('vi-VN').format(order.totalPrice)}đ`, W / 2, 280);

            ctx.drawImage(qrImgRef.current, (W - qrSize) / 2, 320, qrSize, drawHeight);

            const dataUrl = canvas.toDataURL('image/png');
            const file = dataURLtoFile(dataUrl, `pay-${order.id}.png`);
            if (navigator.share) await navigator.share({ files: [file], title: `Thanh toán #${order.id}` });
            else window.open(dataUrl);
            toast.dismiss(toastId);
        } catch (e) { toast.error("Lỗi tạo ảnh"); toast.dismiss(toastId); }
  };

  const handleDetailAction = {
      call: () => window.open(`tel:${detailOrder?.customerPhone}`, '_self'),
      sms: async () => detailOrder && window.open(`sms:${detailOrder.customerPhone}?body=${encodeURIComponent(await generateDeliveryMessage(detailOrder))}`, '_self'),
      print: () => { /* Logic in Component */ },
      delete: () => detailOrder && handleDeleteClick(detailOrder.id),
      edit: () => detailOrder && handleEdit(detailOrder),
      setStatus: async (s: OrderStatus) => detailOrder && (await storageService.updateStatus(detailOrder.id, s), setDetailOrder({...detailOrder, status: s})),
      confirmPayment: async () => detailOrder && (await storageService.updatePaymentVerification(detailOrder.id, true), setDetailOrder({...detailOrder, paymentVerified: true}), toast.success("Xác nhận tiền về"))
  };

  const filteredOrders = useMemo(() => {
    let result = orders.filter(o => {
      const statusMatch = filterStatus.length === 0 || filterStatus.includes(o.status);
      const batchMatch = filterBatch.length === 0 || (o.batchId && filterBatch.includes(o.batchId));
      if (!statusMatch || !batchMatch) return false;
      if (!deferredSearchTerm) return true;
      const term = normalizeString(deferredSearchTerm);
      return normalizeString(o.customerName).includes(term) || normalizePhone(o.customerPhone).includes(term) || o.id.includes(term.toUpperCase());
    });
    return result.sort((a, b) => b.createdAt - a.createdAt);
  }, [orders, filterStatus, filterBatch, deferredSearchTerm]);

  const clearSelection = () => { setIsSelectionMode(false); setSelectedOrderIds(new Set()); };
  const toggleSelectOrder = (id: string) => {
      const next = new Set(selectedOrderIds);
      if (next.has(id)) next.delete(id); else next.add(id);
      setSelectedOrderIds(next);
      setIsSelectionMode(next.size > 0);
  };

  const confirmDelete = async () => {
    if (deleteId) {
      await storageService.deleteOrder(deleteId);
      toast.success('Đã xóa đơn & hoàn kho!');
      setShowDeleteConfirm(false);
      if(detailOrder?.id === deleteId) setDetailOrder(null);
    }
  };

  return (
    <div className="animate-fade-in pb-32">
      {/* FILTER BAR */}
      <div className="sticky top-16 z-30 bg-white border-b border-gray-200 p-3 shadow-sm rounded-xl mb-4">
          <div className="flex gap-2">
              <input 
                  placeholder="Tìm đơn hàng..." 
                  value={searchTerm} 
                  onChange={e => setSearchTerm(e.target.value)} 
                  className="flex-grow p-2 bg-gray-100 rounded-lg outline-none text-sm"
              />
              <button onClick={() => setIsCompactMode(!isCompactMode)} className="p-2 border rounded-lg bg-white"><i className={`fas ${isCompactMode ? 'fa-list' : 'fa-th'}`}></i></button>
              <button onClick={() => setShowStatsModal(true)} className="p-2 bg-purple-50 text-purple-600 rounded-lg"><i className="fas fa-cubes"></i></button>
              <button onClick={() => setShowReconcileModal(true)} className="p-2 bg-green-50 text-green-600 rounded-lg"><i className="fas fa-file-invoice-dollar"></i></button>
          </div>
      </div>

      {/* LIST */}
      <div className={isCompactMode ? "bg-white rounded-xl shadow-sm border overflow-hidden" : "grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4"}>
        {filteredOrders.slice(0, visibleCount).map((order, idx) => (
            <OrderCard 
                key={order.id} 
                order={order} 
                onDelete={handleDeleteClick} 
                onEdit={handleEdit} 
                index={idx}
                isCompactMode={isCompactMode}
                onViewDetail={handleViewDetail}
                onShowQR={handleShowQR}
                onShip={handleShipOrder}
                isSelectionMode={isSelectionMode}
                isSelected={selectedOrderIds.has(order.id)}
                onToggleSelect={toggleSelectOrder}
                onLongPress={id => { setIsSelectionMode(true); toggleSelectOrder(id); }}
                onUpdate={() => {}}
            />
        ))}
      </div>

      {/* BULK BAR */}
      {isSelectionMode && (
          <div className="fixed bottom-6 left-1/2 -translate-x-1/2 bg-black text-white px-6 py-4 rounded-2xl shadow-2xl flex items-center gap-6 z-50 animate-bounce-in">
              <span className="font-bold">Đã chọn {selectedOrderIds.size}</span>
              <button onClick={() => setShowBulkStatusModal(true)} className="text-blue-400 font-bold">Status</button>
              <button onClick={() => setShowBulkDeleteConfirm(true)} className="text-red-400 font-bold">Xóa</button>
              <button onClick={clearSelection} className="text-gray-400">Hủy</button>
          </div>
      )}

      {/* DETAIL MODAL */}
      {detailOrder && (
          <div className="fixed inset-0 z-[100] bg-black/60 backdrop-blur-sm flex items-center justify-center p-4 animate-fade-in" onClick={() => setDetailOrder(null)}>
              <div className="bg-white rounded-3xl w-full max-w-md shadow-2xl overflow-hidden" onClick={e => e.stopPropagation()}>
                  <div className="p-6 border-b flex justify-between items-center bg-gray-50">
                      <h3 className="font-black text-2xl">Đơn #{detailOrder.id}</h3>
                      <button onClick={() => setDetailOrder(null)}><i className="fas fa-times text-xl text-gray-400"></i></button>
                  </div>
                  <div className="p-6 space-y-4">
                      <div className="flex items-center gap-4 bg-eco-50 p-4 rounded-2xl">
                          <div className="w-12 h-12 bg-eco-600 rounded-full flex items-center justify-center text-white font-bold text-xl">{detailOrder.customerName.charAt(0)}</div>
                          <div>
                              <div className="font-bold text-lg">{detailOrder.customerName}</div>
                              <div className="text-gray-500 font-mono">{detailOrder.customerPhone}</div>
                          </div>
                      </div>
                      <div className="text-sm font-medium text-gray-700 bg-gray-50 p-3 rounded-xl border border-dashed border-gray-200">
                          <i className="fas fa-map-marker-alt text-red-500 mr-2"></i>{detailOrder.address}
                      </div>
                      <div className="divide-y border rounded-2xl overflow-hidden">
                          {detailOrder.items.map((it, i) => (
                              <div key={i} className="p-3 flex justify-between text-sm">
                                  <span>{it.name} x{it.quantity}</span>
                                  <span className="font-bold">{new Intl.NumberFormat('vi-VN').format(it.price * it.quantity)}đ</span>
                              </div>
                          ))}
                      </div>
                      <div className="flex justify-between items-center px-2">
                          <span className="font-bold text-gray-400">TỔNG CỘNG</span>
                          <span className="font-black text-2xl">{new Intl.NumberFormat('vi-VN').format(detailOrder.totalPrice)}đ</span>
                      </div>
                  </div>
                  <div className="p-4 grid grid-cols-2 gap-2 bg-gray-50">
                      <button onClick={handleDetailAction.setStatus.bind(null, OrderStatus.DELIVERED)} className="col-span-2 py-3 bg-eco-600 text-white rounded-xl font-bold">HOÀN TẤT ĐƠN</button>
                      <button onClick={handleDetailAction.edit} className="py-2 bg-white border rounded-xl font-bold">Sửa đơn</button>
                      <button onClick={handleDetailAction.delete} className="py-2 bg-red-50 text-red-600 rounded-xl font-bold">Xóa đơn</button>
                  </div>
              </div>
          </div>
      )}

      {/* QR MODAL */}
      {qrState.isOpen && (
          <div className="fixed inset-0 z-[100] bg-black/80 backdrop-blur-md flex items-center justify-center p-4 animate-fade-in" onClick={() => setQrState({...qrState, isOpen: false})}>
              <div className="bg-white rounded-[2.5rem] p-8 w-full max-w-sm text-center shadow-2xl" onClick={e => e.stopPropagation()}>
                  <h3 className="font-black text-gray-800 text-xl mb-4">THANH TOÁN #{qrState.order?.id}</h3>
                  <div className="bg-gray-100 p-4 rounded-3xl mb-6">
                      <img src={qrState.url} alt="QR" className="w-full h-auto rounded-xl" />
                  </div>
                  <div className="grid grid-cols-2 gap-3">
                      <button onClick={handleShareQR} className="py-4 bg-gray-100 rounded-2xl font-bold">Chia sẻ</button>
                      <button onClick={() => setQrState({...qrState, isOpen: false})} className="py-4 bg-black text-white rounded-2xl font-bold">Đóng</button>
                  </div>
              </div>
          </div>
      )}

      {/* OTHER MODALS */}
      {shipmentOrder && <ShipmentModal isOpen={showShipmentModal} onClose={() => setShowShipmentModal(false)} order={shipmentOrder} onSuccess={handleShipmentSuccess} />}
      <ConfirmModal isOpen={showDeleteConfirm} title="Xóa đơn hàng?" message="Hàng hóa sẽ được tự động hoàn lại kho." onConfirm={confirmDelete} onCancel={() => setShowDeleteConfirm(false)} isDanger={true} />
    </div>
  );
};

