  const [editingProduct, setEditingProduct] = useState<Product | null>(null);
  const [editProductMode, setEditProductMode] = useState<'IMPORT' | 'SET'>('SET');

  const [showRoutePlanner, setShowRoutePlanner] = useState(false);
  const [showShipmentModal, setShowShipmentModal] = useState(false);
  const [shipmentOrder, setShipmentOrder] = useState<Order | null>(null);

  const [moveBatchData, setMoveBatchData] = useState<{isOpen: boolean, targetBatch: string}>({ isOpen: false, targetBatch: '' });
  const [qrState, setQrState] = useState<{ isOpen: boolean, url: string, order: Order | null }>({ isOpen: false, url: '', order: null });
  const [detailOrder, setDetailOrder] = useState<Order | null>(null);
  const [visibleCount, setVisibleCount] = useState(20);

  const qrImgRef = useRef<HTMLImageElement | null>(null);
  const shopConfigRef = useRef<ShopConfig | null>(null);
  const bankConfigRef = useRef<BankConfig | null>(null);

  const statusLabels: Record<OrderStatus, string> = { 
    [OrderStatus.PENDING]: 'Chờ xử lý', 
    [OrderStatus.PICKED_UP]: 'Đã lấy hàng', 
    [OrderStatus.IN_TRANSIT]: 'Đang giao', 
    [OrderStatus.DELIVERED]: 'Đã giao', 
    [OrderStatus.CANCELLED]: 'Đã hủy' 
  };

  // Header Observer Logic
  useEffect(() => {
      const observer = new IntersectionObserver(
          ([entry]) => { setIsHeaderVisible(entry.isIntersecting); setActiveDropdown(null); },
          { threshold: 0, rootMargin: "-70px 0px 0px 0px" }
      );
      if (observerTarget.current) observer.observe(observerTarget.current);
      return () => observer.disconnect();
  }, []);

  useEffect(() => {
    const unsubOrders = storageService.subscribeOrders(setOrders);
    const unsubProducts = storageService.subscribeProducts(setProducts);
    const unsubCustomers = storageService.subscribeCustomers(setCustomers);
    const handleWindowEvents = () => setActiveDropdown(null);
    window.addEventListener('resize', handleWindowEvents);
    window.addEventListener('scroll', handleWindowEvents, true);
    return () => { 
        if (unsubOrders) unsubOrders(); 
        if (unsubProducts) unsubProducts();
        if (unsubCustomers) unsubCustomers(); 
        window.removeEventListener('resize', handleWindowEvents); 
        window.removeEventListener('scroll', handleWindowEvents, true); 
    };
  }, []);

  useEffect(() => {
      if (qrState.isOpen && qrState.url) {
          storageService.getShopConfig().then(c => shopConfigRef.current = c);
          storageService.getBankConfig().then(c => bankConfigRef.current = c);
          const img = new Image();
          img.crossOrigin = "Anonymous";
          img.src = qrState.url;
          img.onload = () => { qrImgRef.current = img; };
      } else { qrImgRef.current = null; }
  }, [qrState.isOpen, qrState.url]);

  useEffect(() => {
      const handleClickOutside = (event: MouseEvent) => {
          if (activeEditProductRow !== null && !(event.target as Element).closest('.product-dropdown-container')) setActiveEditProductRow(null);
          if (activeDropdown) {
              const dropdownEl = document.getElementById('floating-dropdown-portal');
              const statusBtn = statusDropdownBtnRef.current;
              const batchBtn = batchDropdownBtnRef.current;
              if (dropdownEl && !dropdownEl.contains(event.target as Node) && statusBtn && !statusBtn.contains(event.target as Node) && batchBtn && !batchBtn.contains(event.target as Node)) setActiveDropdown(null);
          }
      };
      document.addEventListener('mousedown', handleClickOutside);
      return () => document.removeEventListener('mousedown', handleClickOutside);
  }, [activeEditProductRow, activeDropdown]);

  // Core Actions
  const handleViewDetail = (order: Order) => setDetailOrder(order);
  const handleDeleteClick = useCallback((id: string) => { setDeleteId(id); setShowDeleteConfirm(true); }, []);
  const handleEdit = useCallback((order: Order) => { setEditingOrder(JSON.parse(JSON.stringify(order))); setActiveEditProductRow(null); setDetailOrder(null); }, []);
  const handleSplitBatch = useCallback(async (order: Order) => { await storageService.splitOrderToNextBatch(order.id, order.batchId); toast.success('Đã chuyển đơn sang lô sau!'); if(detailOrder?.id === order.id) setDetailOrder(null); }, [detailOrder]);

  const handleShowQR = useCallback(async (order: Order) => { 
      const bank = await storageService.getBankConfig(); 
      if (!bank?.accountNo) return toast.error("Chưa cài đặt Ngân hàng."); 
      const url = `https://img.vietqr.io/image/${bank.bankId}-${bank.accountNo}-${bank.template || 'compact2'}.png?amount=${order.totalPrice}&addInfo=${encodeURIComponent('DH '+order.id)}&accountName=${encodeURIComponent(bank.accountName)}`; 
      setQrState({ isOpen: true, url, order }); 
  }, []);

  const handleShipOrder = (order: Order) => { setShipmentOrder(order); setShowShipmentModal(true); };
  const handleShipmentSuccess = async (carrierData: CarrierData) => {
      if (shipmentOrder) {
          const updated = { ...shipmentOrder, carrierData, status: OrderStatus.PICKED_UP };
          await storageService.updateOrderDetails(updated);
          if (detailOrder?.id === shipmentOrder.id) setDetailOrder(updated);
      }
  };

  const handleShareQR = async () => {
        if (!qrState.url || !qrState.order || !qrImgRef.current) return;
        const toastId = toast.loading("Đang tạo ảnh...");
        try {
            const order = qrState.order;
            const shop = shopConfigRef.current;
            const bank = bankConfigRef.current;
            const W = 800; const qrSize = 500;
            let H = 650 + (order.items.length * 50);
            const canvas = document.createElement('canvas');
            const ctx = canvas.getContext('2d')!;
            canvas.width = W; canvas.height = H;
            ctx.fillStyle = '#ffffff'; ctx.fillRect(0, 0, W, H);
            ctx.fillStyle = '#15803d'; ctx.fillRect(0, 0, W, 140);
            ctx.fillStyle = '#ffffff'; ctx.font = 'bold 40px Arial'; ctx.textAlign = 'center';
            ctx.fillText('QUÉT MÃ THANH TOÁN', W / 2, 70);
            ctx.fillStyle = '#374151'; ctx.font = 'bold 32px Arial';
            ctx.fillText((shop?.shopName || 'ECOGO LOGISTICS').toUpperCase(), W / 2, 165);
            ctx.fillStyle = '#f0fdf4'; ctx.fillRect(100, 200, 600, 100);
            ctx.fillStyle = '#15803d'; ctx.font = 'bold 60px Arial';
            ctx.fillText(`${new Intl.NumberFormat('vi-VN').format(order.totalPrice)}đ`, W / 2, 265);
            ctx.drawImage(qrImgRef.current, (W - qrSize) / 2, 320, qrSize, qrSize);
            const dataUrl = canvas.toDataURL('image/png');
            const file = dataURLtoFile(dataUrl, `pay-${order.id}.png`);
            if (navigator.share) await navigator.share({ files: [file], title: `Thanh toán #${order.id}` });
            else { const a = document.createElement('a'); a.href = dataUrl; a.download = `pay-${order.id}.png`; a.click(); }
            toast.dismiss(toastId);
        } catch (e) { toast.error("Lỗi tạo ảnh"); toast.dismiss(toastId); }
  };

  const handleDetailAction = {
      call: () => window.open(`tel:${detailOrder?.customerPhone}`, '_self'),
      sms: async () => { if(detailOrder) { const msg = await generateDeliveryMessage(detailOrder); window.open(`sms:${detailOrder.customerPhone}?body=${encodeURIComponent(msg)}`, '_self'); } },
      zalo: () => { if(detailOrder) window.open(`https://zalo.me/${detailOrder.customerPhone.replace(/^0/,'84')}`, '_blank'); },
      print: () => { if(detailOrder) { /* Logic in JSX below */ } },
      delete: () => { if(detailOrder) { handleDeleteClick(detailOrder.id); setDetailOrder(null); } },
      edit: () => { if(detailOrder) { setEditingOrder(JSON.parse(JSON.stringify(detailOrder))); setDetailOrder(null); } },
      setStatus: async (s: OrderStatus) => { if(detailOrder) { await storageService.updateStatus(detailOrder.id, s); setDetailOrder({...detailOrder, status: s}); } },
      confirmPayment: async () => { if(detailOrder) { await storageService.updatePaymentVerification(detailOrder.id, true); setDetailOrder({...detailOrder, paymentVerified: true}); toast.success("Đã xác nhận thanh toán"); } },
      splitBatch: () => { if(detailOrder) handleSplitBatch(detailOrder); },
      showQR: () => { if(detailOrder) handleShowQR(detailOrder); },
      ship: () => { if(detailOrder) handleShipOrder(detailOrder); }
  };

  const batches = useMemo(() => {
    const activity = new Map<string, number>();
    orders.forEach(o => { if (o.batchId) activity.set(o.batchId, Math.max(activity.get(o.batchId) || 0, o.createdAt)); });
    return Array.from(activity.entries()).sort((a, b) => b[1] - a[1]).map(e => e[0]).slice(0, 50);
  }, [orders]);

  const customerMap = useMemo(() => {
    const map = new Map<string, Customer>();
    customers.forEach(c => map.set(c.id, c));
    return map;
  }, [customers]);

  const findCustomerForOrder = (order: Order): Customer | undefined => {
    if (order.customerId && customerMap.has(order.customerId)) return customerMap.get(order.customerId);
    return storageService.findMatchingCustomer(order.customerPhone, order.address, order.customerId);
  };

  const filteredOrders = useMemo(() => {
    let result = orders.filter(o => {
      const statusMatch = filterStatus.length === 0 || filterStatus.includes(o.status);
      const batchMatch = filterBatch.length === 0 || (o.batchId && filterBatch.includes(o.batchId));
      if (!statusMatch || !batchMatch) return false;
      if (!deferredSearchTerm) return true;
      const term = normalizeString(deferredSearchTerm);
      return normalizeString(o.customerName).includes(term) || normalizePhone(o.customerPhone).includes(term) || normalizeString(o.address).includes(term) || o.items.some(i => normalizeString(i.name).includes(term));
    });
    if (sortBy === 'NEWEST') return result.sort((a, b) => b.createdAt - a.createdAt);
    if (sortBy === 'STATUS') return result.sort((a, b) => a.status.localeCompare(b.status));
    if (sortBy === 'ROUTE') return result.sort((a, b) => (a.orderIndex || 0) - (b.orderIndex || 0));
    return result;
  }, [orders, filterStatus, filterBatch, deferredSearchTerm, sortBy]);

  const batchStatsData = useMemo(() => {
      const statsMap = new Map<string, { name: string, qtyOrdered: number, productInfo?: Product }>();
      const targetOrders = filterBatch.length > 0 ? orders.filter(o => o.batchId && filterBatch.includes(o.batchId)) : orders;
      targetOrders.filter(o => o.status !== OrderStatus.CANCELLED).forEach(o => {
          o.items.forEach(it => {
              const name = it.name.trim(); if (!name) return;
              const cur = statsMap.get(name) || { name, qtyOrdered: 0 };
              cur.qtyOrdered += it.quantity; statsMap.set(name, cur);
          });
      });
      return Array.from(statsMap.values()).map(it => {
          const norm = normalizeString(it.name);
          const prod = products.find(p => normalizeString(p.name) === norm) || products.find(p => normalizeString(p.name).includes(norm));
          return { ...it, productInfo: prod };
      }).sort((a, b) => a.name.localeCompare(b.name));
  }, [orders, products, filterBatch]);

  const handleLongPress = useCallback((id: string) => { setIsSelectionMode(true); setSelectedOrderIds(new Set([id])); if (navigator.vibrate) navigator.vibrate(50); }, []);
  const toggleSelectOrder = useCallback((id: string) => { setSelectedOrderIds(prev => { const next = new Set(prev); if (next.has(id)) next.delete(id); else next.add(id); setIsSelectionMode(next.size > 0); return next; }); }, []);
  const clearSelection = () => { setIsSelectionMode(false); setSelectedOrderIds(new Set()); };

  const executeBulkDelete = async () => { 
    if (selectedOrderIds.size === 0) return; 
    await storageService.deleteOrdersBatch(Array.from(selectedOrderIds) as string[]); 
    toast.success(`Đã xóa & hoàn kho xong!`); clearSelection(); setShowBulkDeleteConfirm(false); 
  };
  const executeBulkSplit = async () => { 
    const subset = orders.filter(o => selectedOrderIds.has(o.id)).map(o => ({ id: o.id, batchId: o.batchId }));
    await storageService.splitOrdersBatch(subset); toast.success(`Đã hoãn đơn hàng!`); clearSelection(); 
  };
  const executeBulkStatusUpdate = async (status: OrderStatus) => {
    const promises = Array.from(selectedOrderIds).map(id => storageService.updateStatus(id as string, status));
    await Promise.all(promises); toast.success(`Đã cập nhật trạng thái!`); setShowBulkStatusModal(false); clearSelection();
  };

  // Drag handlers
  const handleTouchStart = useCallback((e: React.TouchEvent<HTMLDivElement>, pos: number) => { if (sortBy !== 'ROUTE') return; dragItem.current = pos; e.currentTarget.closest('.order-row')?.classList.add('opacity-50', 'bg-yellow-50'); }, [sortBy]);
  const handleTouchMove = useCallback((e: React.TouchEvent<HTMLDivElement>) => {
    if (sortBy !== 'ROUTE' || dragItem.current === null) return;
    const touch = e.touches[0]; const el = document.elementFromPoint(touch.clientX, touch.clientY);
    const row = el?.closest('[data-index]');
    if (row) {
        const newIdx = parseInt(row.getAttribute('data-index') || '-1');
        if (newIdx !== -1 && newIdx !== dragItem.current) {
            const list = [...filteredOrders.slice(0, visibleCount)];
            const item = list.splice(dragItem.current, 1)[0];
            list.splice(newIdx, 0, item);
            dragItem.current = newIdx;
            const reindexed = list.map((o, i) => ({ ...o, orderIndex: i }));
            storageService.saveOrdersList(reindexed);
        }
    }
  }, [sortBy, filteredOrders, visibleCount]);

  const handleDragStart = (e: React.DragEvent, index: number) => { dragItem.current = index; e.currentTarget.closest('.order-row')?.classList.add('opacity-40'); };
  const handleDragEnter = (e: React.DragEvent, index: number) => { dragOverItem.current = index; e.preventDefault(); };
  const handleDragEnd = () => {
      if (dragItem.current !== null && dragOverItem.current !== null && sortBy === 'ROUTE') {
          const list = [...filteredOrders.slice(0, visibleCount)];
          const item = list.splice(dragItem.current, 1)[0];
          list.splice(dragOverItem.current, 0, item);
          const reindexed = list.map((o, i) => ({ ...o, orderIndex: i }));
          storageService.saveOrdersList(reindexed);
      }
      dragItem.current = null; dragOverItem.current = null;
      document.querySelectorAll('.order-row').forEach(r => r.classList.remove('opacity-40', 'opacity-50', 'bg-yellow-50'));
  };

  return (
    <div className="animate-fade-in pb-32">
      {/* 1. STICKY FILTER & SEARCH */}
      <div className="sticky top-16 z-30 bg-gray-50/95 backdrop-blur-sm shadow-sm">
         <div className="bg-white border-b border-gray-200 p-2 shadow-sm">
             <div className="flex gap-2 items-center mb-2">
                <div className="relative flex-grow">
                    <i className="fas fa-search absolute left-3 top-2.5 text-gray-400 text-xs"></i>
                    <input placeholder="Tìm tên, sđt, địa chỉ, hàng hóa..." value={searchTerm} onChange={e => setSearchTerm(e.target.value)} className="w-full pl-9 pr-9 py-2 rounded-lg bg-gray-100 border-transparent focus:bg-white focus:ring-2 focus:ring-eco-100 text-sm font-medium outline-none transition-all" />
                    <button onClick={() => { /* Voice search logic */ }} className={`absolute right-2 top-1.5 w-7 h-7 rounded-full flex items-center justify-center transition-colors ${isListeningSearch ? 'bg-red-500 text-white' : 'text-gray-400 hover:bg-gray-200'}`}><i className="fas fa-microphone"></i></button>
                </div>
                <button onClick={() => setIsCompactMode(!isCompactMode)} className={`w-9 h-9 flex-shrink-0 flex items-center justify-center rounded-lg border transition-all ${isCompactMode ? 'bg-eco-100 text-eco-700' : 'bg-white text-gray-400'}`}><i className={`fas ${isCompactMode ? 'fa-list' : 'fa-th-large'}`}></i></button>
                <button onClick={() => setOrdersToPrint(filteredOrders)} className="w-9 h-9 flex-shrink-0 flex items-center justify-center rounded-lg bg-white text-gray-500 border border-gray-200"><i className="fas fa-print"></i></button>
                <button onClick={() => setShowStatsModal(true)} className="w-9 h-9 flex-shrink-0 flex items-center justify-center rounded-lg bg-white text-gray-500 border border-gray-200"><i className="fas fa-cubes"></i></button>
                <button onClick={() => setShowReconcileModal(true)} className="w-9 h-9 flex-shrink-0 flex items-center justify-center rounded-lg bg-white text-gray-500 border border-gray-200"><i className="fas fa-file-invoice-dollar"></i></button>
             </div>
             <div className={`grid transition-all duration-300 ease-out ${isHeaderVisible ? 'grid-rows-[1fr]' : 'grid-rows-[0fr]'}`}>
                <div className="overflow-hidden">
                    <div className="flex gap-2 overflow-x-auto no-scrollbar pb-1">
                        <div className="relative flex-1 min-w-[100px]">
                             <button ref={batchDropdownBtnRef} onClick={() => { const r = batchDropdownBtnRef.current?.getBoundingClientRect(); if(r) { setDropdownPos({top: r.bottom+4, left: r.left, width: r.width}); setActiveDropdown('BATCH'); } }} className="w-full pl-2 pr-6 py-1.5 rounded-lg bg-gray-50 border text-xs font-bold text-gray-700 text-left flex justify-between items-center outline-none">
                                 <span className="truncate">{filterBatch.length ? filterBatch[0] : 'Tất cả Lô'}</span><i className="fas fa-chevron-down text-[8px]"></i>
                             </button>
                        </div>
                        <div className="relative flex-1 min-w-[110px]">
                            <button ref={statusDropdownBtnRef} onClick={() => { const r = statusDropdownBtnRef.current?.getBoundingClientRect(); if(r) { setDropdownPos({top: r.bottom+4, left: r.left, width: r.width}); setActiveDropdown('STATUS'); } }} className="w-full pl-2 pr-6 py-1.5 rounded-lg bg-gray-50 border text-xs font-medium text-gray-700 text-left flex justify-between items-center outline-none">
                                <span className="truncate">{filterStatus.length ? statusLabels[filterStatus[0]] : 'Trạng thái'}</span><i className="fas fa-chevron-down text-[8px]"></i>
                            </button>
                        </div>
                        <div className="flex bg-gray-100 rounded-lg p-0.5 flex-shrink-0">
                            <button onClick={() => setSortBy('NEWEST')} className={`px-2 py-1 rounded-md text-[10px] font-bold ${sortBy === 'NEWEST' ? 'bg-white shadow-sm' : 'text-gray-400'}`}>Mới</button>
                            <button onClick={() => setShowRoutePlanner(true)} className={`px-2 py-1 rounded-md text-[10px] font-bold ${sortBy === 'ROUTE' ? 'bg-white shadow-sm text-eco-700' : 'text-gray-400'}`}><i className="fas fa-map-marked-alt"></i> Lộ trình</button>
                        </div>
                    </div>
                </div>
             </div>
         </div>
      </div>

      {/* Floating Dropdown Portal */}
      {activeDropdown && (
        <div id="floating-dropdown-portal" className="fixed z-[9999] bg-white border rounded-lg shadow-xl max-h-60 overflow-y-auto p-1 animate-fade-in" style={{ top: dropdownPos.top, left: dropdownPos.left, minWidth: dropdownPos.width }}>
            <div onClick={() => activeDropdown === 'STATUS' ? setFilterStatus([]) : setFilterBatch([])} className="px-3 py-2 rounded-md text-xs font-bold cursor-pointer hover:bg-gray-50 flex items-center gap-2">Tất cả</div>
            {activeDropdown === 'STATUS' ? Object.entries(statusLabels).map(([k, l]) => (
                <div key={k} onClick={() => setFilterStatus(prev => prev.includes(k as any) ? prev.filter(x => x !== k) : [...prev, k as any])} className={`px-3 py-2 rounded-md text-xs cursor-pointer flex items-center gap-2 ${filterStatus.includes(k as any) ? 'bg-blue-50 text-blue-700' : 'hover:bg-gray-50'}`}>{l}</div>
            )) : batches.map(b => (
                <div key={b} onClick={() => setFilterBatch(prev => prev.includes(b) ? prev.filter(x => x !== b) : [...prev, b])} className={`px-3 py-2 rounded-md text-xs cursor-pointer flex items-center gap-2 ${filterBatch.includes(b) ? 'bg-blue-50 text-blue-700' : 'hover:bg-gray-50'}`}>{b}</div>
            ))}
        </div>
      )}

      {/* 2. ORDER LIST */}
      <div ref={observerTarget} className="h-px w-full opacity-0"></div>
      <div className={isCompactMode ? 'bg-white rounded-xl shadow-sm border overflow-hidden flex flex-col divide-y divide-gray-100 mt-1' : 'grid grid-cols-1 md:grid-cols-2 xl:grid-cols-3 gap-4 mt-2'}>
        {filteredOrders.slice(0, visibleCount).map((order, index) => (
            <div key={order.id} data-index={index} className="order-row transition-all duration-200">
                <OrderCard 
                    order={order} index={index}
                    isCompactMode={isCompactMode} isSortMode={sortBy === 'ROUTE'}
                    onDelete={handleDeleteClick} onEdit={handleEdit} onUpdate={() => {}}
                    onLongPress={handleLongPress} onToggleSelect={toggleSelectOrder}
                    isSelected={selectedOrderIds.has(order.id)} isSelectionMode={isSelectionMode}
                    onShowQR={handleShowQR} onViewDetail={handleViewDetail} onShip={handleShipOrder}
                    onSplitBatch={handleSplitBatch}
                    onTouchStart={e => handleTouchStart(e, index)} onTouchMove={handleTouchMove}
                    onRowDragStart={handleDragStart} onRowDragEnter={handleDragEnter} onDragEnd={handleDragEnd}
                    customerData={findCustomerForOrder(order)}
                />
            </div>
        ))}
      </div>

      {visibleCount < filteredOrders.length && (
          <div className="mt-6 text-center"><button onClick={() => setVisibleCount(v => v + 20)} className="bg-gray-100 px-6 py-2 rounded-xl font-bold text-gray-600">Xem thêm</button></div>
      )}

      {/* 3. MODALS */}
      {detailOrder && (
          <div className="fixed inset-0 z-[100] bg-black/60 backdrop-blur-sm flex items-center justify-center p-4 animate-fade-in" onClick={() => setDetailOrder(null)}>
              <div className="bg-white rounded-2xl shadow-2xl w-full max-w-md overflow-hidden flex flex-col max-h-[90vh] animate-scale-in" onClick={e => e.stopPropagation()}>
                  <div className="p-4 border-b flex justify-between items-center bg-gray-50/50">
                      <h3 className="font-black text-xl">Đơn #{detailOrder.id}</h3>
                      <button onClick={() => setDetailOrder(null)} className="w-8 h-8 rounded-full bg-white flex items-center justify-center text-gray-400"><i className="fas fa-times"></i></button>
                  </div>
                  <div className="flex-grow overflow-y-auto p-4 space-y-4">
                      <div className="bg-eco-50 p-4 rounded-2xl flex items-center gap-4">
                          <div className="w-12 h-12 bg-eco-600 rounded-full flex items-center justify-center text-white font-black text-xl">{detailOrder.customerName.charAt(0)}</div>
                          <div><div className="font-bold text-lg">{detailOrder.customerName}</div><div className="text-gray-500 font-mono text-sm">{detailOrder.customerPhone}</div></div>
                      </div>
                      <div className="text-sm text-gray-600 leading-relaxed pl-2 border-l-4 border-red-500"><i className="fas fa-map-marker-alt text-red-500 mr-2"></i>{detailOrder.address}</div>
                      <div className="space-y-2">
                          {detailOrder.items.map((it, i) => (
                              <div key={i} className="flex justify-between p-3 bg-gray-50 rounded-xl">
                                  <span className="font-bold text-gray-700">{it.name} x{it.quantity}</span>
                                  <span className="font-bold text-blue-600">{new Intl.NumberFormat('vi-VN').format(it.price * it.quantity)}đ</span>
                              </div>
                          ))}
                      </div>
                  </div>
                  <div className="p-4 bg-gray-50 grid grid-cols-2 gap-2">
                      <button onClick={() => handleDetailAction.setStatus(OrderStatus.DELIVERED)} className="col-span-2 py-3 bg-black text-white rounded-xl font-bold shadow-lg">HOÀN TẤT ĐƠN</button>
                      <button onClick={handleDetailAction.edit} className="py-2 bg-white border rounded-xl font-bold">Sửa</button>
                      <button onClick={handleDetailAction.delete} className="py-2 bg-red-50 text-red-600 rounded-xl font-bold">Xóa</button>
                  </div>
              </div>
          </div>
      )}

      {qrState.isOpen && qrState.order && (
          <div className="fixed inset-0 z-[100] bg-black/80 backdrop-blur-md flex items-center justify-center p-4 animate-fade-in" onClick={() => setQrState({...qrState, isOpen: false})}>
              <div className="bg-white rounded-3xl p-8 w-full max-w-sm text-center shadow-2xl animate-scale-in" onClick={e => e.stopPropagation()}>
                  <h3 className="font-black text-xl mb-4">THANH TOÁN #{qrState.order.id}</h3>
                  <div className="bg-gray-100 p-4 rounded-2xl mb-6 shadow-inner"><img src={qrState.url} alt="QR" className="w-full h-auto rounded-xl" /></div>
                  <div className="grid grid-cols-2 gap-3"><button onClick={handleShareQR} className="py-3 bg-gray-100 rounded-xl font-bold">Chia sẻ</button><button onClick={() => setQrState({...qrState, isOpen: false})} className="py-3 bg-black text-white rounded-xl font-bold">Đóng</button></div>
              </div>
          </div>
      )}

      {/* Selection Action Bar */}
      {isSelectionMode && (
          <div className="fixed bottom-6 left-1/2 -translate-x-1/2 bg-gray-900 text-white px-6 py-4 rounded-2xl shadow-2xl flex items-center gap-8 z-50 animate-bounce-in border border-gray-700">
              <div className="flex flex-col"><span className="text-[10px] text-gray-400 font-bold uppercase">Đã chọn</span><span className="font-black text-eco-400">{selectedOrderIds.size} đơn</span></div>
              <div className="flex gap-6">
                  <button onClick={() => setShowBulkStatusModal(true)} className="flex flex-col items-center gap-1"><i className="fas fa-exchange-alt text-blue-400"></i><span className="text-[9px] font-bold">Status</span></button>
                  <button onClick={() => setShowBulkDeleteConfirm(true)} className="flex flex-col items-center gap-1"><i className="fas fa-trash-alt text-red-400"></i><span className="text-[9px] font-bold">Xóa</span></button>
                  <button onClick={clearSelection} className="flex flex-col items-center gap-1"><i className="fas fa-times text-gray-400"></i><span className="text-[9px] font-bold">Hủy</span></button>
              </div>
          </div>
      )}

      {/* Confirmation & Secondary Modals */}
      {shipmentOrder && <ShipmentModal isOpen={showShipmentModal} onClose={() => setShowShipmentModal(false)} order={shipmentOrder} onSuccess={handleShipmentSuccess} />}
      <ConfirmModal isOpen={showDeleteConfirm} title="Xóa đơn hàng?" message="Dữ liệu sẽ bị xóa vĩnh viễn và hàng sẽ được hoàn vào kho." onConfirm={async () => { if(deleteId) { await storageService.deleteOrder(deleteId); toast.success('Đã xóa!'); setShowDeleteConfirm(false); setDeleteId(null); if(detailOrder?.id === deleteId) setDetailOrder(null); } }} onCancel={() => setShowDeleteConfirm(false)} isDanger={true} />
      <ConfirmModal isOpen={showBulkDeleteConfirm} title={`Xóa ${selectedOrderIds.size} đơn hàng?`} message="Toàn bộ hàng hóa sẽ được hoàn trả vào kho tự động." onConfirm={executeBulkDelete} onCancel={() => setShowBulkDeleteConfirm(false)} isDanger={true} />
      <RoutePlannerModal isOpen={showRoutePlanner} onClose={() => setShowRoutePlanner(false)} orders={filteredOrders} onApplySort={(list) => { storageService.saveOrdersList(list.map((o, i) => ({ ...o, orderIndex: i }))); setSortBy('ROUTE'); }} />
    </div>
  );
};

export default TrackingDashboard;
